// Genera número correlativo DC-YYYY/NNNN (solo facturas emitidas)
function genNumeroFactura(facturas, year) {
  const prefix = `DC-${year}/`;
  const nums   = facturas
    .filter(f => f.modo === "emitida" && f.numero && f.numero.startsWith(prefix))
    .map(f => parseInt(f.numero.replace(prefix, ""), 10) || 0);
  const next = nums.length > 0 ? Math.max(...nums) + 1 : 1;
  return `${prefix}${String(next).padStart(4, "0")}`;
}

// ── Cálculo por línea ──────────────────────────────────────
// aplicarRecargo se puede pasar a nivel de línea (l.aplicarRecargo)
// o como argumento externo (para compatibilidad con facturas antiguas)
function calcLinea(l, recargoGlobal = false) {
  const base        = (parseFloat(l.cantidad) || 0) * (parseFloat(l.precioUnitario) || 0);
  const descAmt     = base * ((parseFloat(l.descuento) || 0) / 100);
  const baseConDesc = base - descAmt;
  const ivaAmt      = l.exento ? 0 : baseConDesc * ((parseFloat(l.tipoIVA) || 0) / 100);
  const conRecargo  = !l.exento && (l.aplicarRecargo || recargoGlobal);
  const recargoAmt  = conRecargo ? baseConDesc * ((RECARGO_MAP[parseInt(l.tipoIVA)] || 0) / 100) : 0;
  const recargoPct  = conRecargo ? (RECARGO_MAP[parseInt(l.tipoIVA)] || 0) : 0;
  return { base, descAmt, baseConDesc, ivaAmt, recargoAmt, recargoPct };
}

function calcFactura(lineas, retencionPct, aplicarRecargo) {
  let totalBase = 0, totalIVA = 0, totalRecargo = 0;
  (lineas || []).forEach(l => {
    const c = calcLinea(l, aplicarRecargo);
    totalBase   += c.baseConDesc;
    totalIVA    += c.ivaAmt;
    totalRecargo += c.recargoAmt;
  });
  const totalRetencion = totalBase * ((parseFloat(retencionPct) || 0) / 100);
  return { totalBase, totalIVA, totalRecargo, totalRetencion, total: totalBase + totalIVA + totalRecargo - totalRetencion };
}

// Agrupa líneas por tipo de IVA para el resumen fiscal.
// Distingue mismo porcentaje con y sin recargo de equivalencia,
// ya que producen bases fiscales distintas en el libro de IVA.
function groupByIVA(lineas, recargoGlobal = false) {
  const map = {};
  (lineas || []).forEach(l => {
    const c      = calcLinea(l, recargoGlobal);
    const conRec = !l.exento && (l.aplicarRecargo || recargoGlobal);
    const key    = l.exento ? "exento" : `${l.tipoIVA}_${conRec?"rec":"norec"}`;
    if (!map[key]) map[key] = {
      tipoIVA:    l.exento ? 0 : parseFloat(l.tipoIVA),
      exento:     !!l.exento,
      conRecargo: conRec,
      recargoPct: c.recargoPct,
      base: 0, ivaAmt: 0, recargoAmt: 0,
    };
    map[key].base       += c.baseConDesc;
    map[key].ivaAmt     += c.ivaAmt;
    map[key].recargoAmt += c.recargoAmt;
  });
  return Object.values(map).sort((a, b) => {
    if (a.exento !== b.exento) return a.exento ? 1 : -1;
    if (a.tipoIVA !== b.tipoIVA) return a.tipoIVA - b.tipoIVA;
    return a.conRecargo ? 1 : -1;
  });
}

// Cálculos nómina
function calcNomina(nomina) {
  const bruto       = parseFloat(nomina.salarioBruto) || 0;
  const extras      = parseFloat(nomina.extras) || 0;
  const baseTotal   = bruto + extras;
  const irpfPct     = parseFloat(nomina.irpfPct) || 0;
  const ssTrabPct   = SS.trabajador.total();
  const ssTrab      = baseTotal * (ssTrabPct / 100);
  const irpfAmt     = baseTotal * (irpfPct / 100);
  const totalDeduc  = ssTrab + irpfAmt;
  const liquidoNeto = baseTotal - totalDeduc;
  const ssEmpresa   = baseTotal * (SS.empresa.total() / 100);
  return {
    bruto, extras, baseTotal, ssTrabPct, ssTrab, irpfPct, irpfAmt, totalDeduc, liquidoNeto, ssEmpresa,
    costeEmpresa: baseTotal + ssEmpresa,
    ssContingencias:    baseTotal * (SS.trabajador.contingencias / 100),
    ssDesempleo:        baseTotal * (SS.trabajador.desempleo / 100),
    ssFormacion:        baseTotal * (SS.trabajador.formacion / 100),
    ssEmpContingencias: baseTotal * (SS.empresa.contingencias / 100),
    ssEmpDesempleo:     baseTotal * (SS.empresa.desempleo / 100),
    ssEmpFogasa:        baseTotal * (SS.empresa.fogasa / 100),
    ssEmpFormacion:     baseTotal * (SS.empresa.formacion / 100),
  };
}

function matchesPeriod(item, mode, value, year) {
  const d = new Date(item.fecha);
  if (d.getFullYear() !== year) return false;
  if (mode === "mes")       return d.getMonth() === value;
  if (mode === "trimestre") return Math.floor(d.getMonth() / 3) === value;
  return true;
}
function getPeriodLabel(mode, value, year) {
  if (mode === "mes")       return `${MONTHS[value]} ${year}`;
  if (mode === "trimestre") return `${Q_NAMES[value]} ${year}`;
  return `Año ${year}`;
}
function summarizeFacturas(flist) {
  // retencionesSop = IRPF que clientes te retienen en tus ventas → reduce Mod. 130
  // retencionesRep = IRPF que tú retienes a profesionales en gastos → a ingresar Mod. 111
  let ingresos = 0, gastos = 0, ivaRep = 0, ivaSop = 0, retencionesSop = 0, retencionesRep = 0;
  flist.forEach(f => {
    const t = calcFactura(f.lineas, f.retencionPct, f.aplicarRecargo);
    if (f.tipo === "venta") {
      ingresos += t.totalBase; ivaRep += t.totalIVA;
      retencionesSop += t.totalRetencion; // IRPF soportado (te descuentan en tu factura)
    } else {
      gastos += t.totalBase; ivaSop += t.totalIVA;
      retencionesRep += t.totalRetencion; // IRPF que debes ingresar en nombre del profesional pagado
    }
  });
  return { ingresos, gastos, ivaRep, ivaSop,
    retenciones: retencionesSop, // alias legacy para Mod. 130
    retencionesSop, retencionesRep,
    beneficio: ingresos - gastos };
}
function summarizeNominas(nlist) {
  let totalBruto=0, totalNeto=0, totalSSTrab=0, totalSSEmp=0, totalIRPF=0, totalCoste=0;
  nlist.forEach(n => {
    const c = calcNomina(n);
    totalBruto += c.baseTotal; totalNeto += c.liquidoNeto; totalSSTrab += c.ssTrab;
    totalSSEmp += c.ssEmpresa; totalIRPF += c.irpfAmt;    totalCoste  += c.costeEmpresa;
  });
  return { totalBruto, totalNeto, totalSSTrab, totalSSEmp, totalIRPF, totalCoste };
}

