function Tag({ children, color = "gray" }) {
  const c = { green:"bg-emerald-50 text-emerald-700 border border-emerald-200", red:"bg-rose-50 text-rose-700 border border-rose-200", amber:"bg-amber-50 text-amber-700 border border-amber-200", gray:"bg-gray-100 text-gray-600 border border-gray-200", indigo:"bg-indigo-50 text-indigo-700 border border-indigo-200", violet:"bg-violet-50 text-violet-700 border border-violet-200", sky:"bg-sky-50 text-sky-700 border border-sky-200", orange:"bg-orange-50 text-orange-700 border border-orange-200" }[color] || "bg-gray-100 text-gray-600";
  return <span className={`text-xs px-2 py-0.5 rounded-full font-semibold ${c}`}>{children}</span>;
}
function KPI({ label, value, sub, accent, tint }) {
  let bg="bg-white border border-gray-200",lc="text-gray-400",vc="text-gray-900",sc="text-gray-400";
  if (accent)           { bg="bg-slate-900";lc="text-slate-400";vc="text-white";sc="text-slate-400"; }
  else if (tint==="green")  { bg="bg-emerald-50 border border-emerald-200";lc="text-emerald-500";vc="text-emerald-900";sc="text-emerald-400"; }
  else if (tint==="red")    { bg="bg-rose-50 border border-rose-200";lc="text-rose-400";vc="text-rose-900";sc="text-rose-300"; }
  else if (tint==="violet") { bg="bg-violet-50 border border-violet-200";lc="text-violet-400";vc="text-violet-900";sc="text-violet-300"; }
  else if (tint==="amber")  { bg="bg-amber-50 border border-amber-200";lc="text-amber-500";vc="text-amber-900";sc="text-amber-400"; }
  else if (tint==="orange") { bg="bg-orange-50 border border-orange-200";lc="text-orange-500";vc="text-orange-900";sc="text-orange-400"; }
  return <div className={`rounded-xl p-5 ${bg}`}><div className={`text-xs font-semibold uppercase tracking-widest mb-2 ${lc}`}>{label}</div><div className={`text-2xl font-bold font-mono ${vc}`}>{value}</div>{sub&&<div className={`text-xs mt-1.5 ${sc}`}>{sub}</div>}</div>;
}
function Divider({ label }) {
  return <div className="flex items-center gap-3 mb-4"><span className="text-xs font-black uppercase tracking-widest text-gray-400 whitespace-nowrap">{label}</span><div className="flex-1 h-px bg-gray-200"/></div>;
}
