function VistaNominas({ nominas, trabajadores, onNew, onView, onDelete, periodMode, periodValue, periodYear }) {
  const filtered = useMemo(() =>
    nominas.filter(n => { const d=new Date(n.fecha); if(d.getFullYear()!==periodYear)return false; if(periodMode==="mes")return d.getMonth()===periodValue; if(periodMode==="trimestre")return Math.floor(d.getMonth()/3)===periodValue; return true; }).sort((a,b) => new Date(b.fecha)-new Date(a.fecha)),
    [nominas,periodMode,periodValue,periodYear]
  );
  const totals = useMemo(() => summarizeNominas(filtered), [filtered]);
  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="text-sm text-gray-500">{filtered.length} nómina{filtered.length!==1?"s":""} en {getPeriodLabel(periodMode,periodValue,periodYear)}</div>
        <button onClick={onNew} className="flex items-center gap-2 bg-violet-700 hover:bg-violet-600 text-white text-xs font-bold px-4 py-2 rounded-xl shadow-md">{Ico.plus} Generar nómina</button>
      </div>
      {filtered.length>0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-2">
          <KPI label="Bruto total" value={fmt(totals.totalBruto)} tint="violet" sub={`${filtered.length} nóminas`}/>
          <KPI label="Neto a pagar" value={fmt(totals.totalNeto)} sub="Líquido trabajadores"/>
          <KPI label="SS total" value={fmt(totals.totalSSTrab+totals.totalSSEmp)} tint="amber" sub="A ingresar TGSS"/>
          <KPI label="Coste empresa" value={fmt(totals.totalCoste)} accent sub="Bruto + SS"/>
        </div>
      )}
      {filtered.length===0
        ? <div className="text-center py-20 bg-white border border-gray-100 rounded-2xl"><div className="text-5xl mb-3">📋</div><div className="text-sm font-semibold text-gray-400">Sin nóminas en {getPeriodLabel(periodMode,periodValue,periodYear)}</div></div>
        : <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["Trabajador","Período","Concepto","Bruto","SS trab.","IRPF","Neto","Coste emp.","Estado",""].map((h,i) => (<th key={i} className={`py-3 px-3 text-xs font-semibold text-gray-500 uppercase tracking-wide ${i===0||i===2?"text-left":"text-right"} ${i===9?"text-center":""}`}>{h}</th>))}</tr>
              </thead>
              <tbody>
                {filtered.map(n => { const c=calcNomina(n); const tw=trabajadores.find(t=>t.id===n.trabajadorId); return (
                  <tr key={n.id} className="border-t border-gray-100 hover:bg-violet-50/30 cursor-pointer group" onClick={() => onView(n)}>
                    <td className="py-2.5 px-3"><div className="font-semibold text-gray-800">{n.trabajadorNombre}</div>{tw?.categoria&&<div className="text-xs text-gray-400">{tw.categoria}</div>}</td>
                    <td className="py-2.5 px-3 text-right text-xs text-gray-600 whitespace-nowrap">{MONTHS_S[n.mes]} {n.anio}</td>
                    <td className="py-2.5 px-3 text-gray-500 text-xs max-w-32 truncate">{n.concepto}</td>
                    <td className="py-2.5 px-3 text-right font-bold font-mono text-gray-900">{fmt(c.baseTotal)}</td>
                    <td className="py-2.5 px-3 text-right text-rose-600 font-mono text-xs">-{fmt(c.ssTrab)}</td>
                    <td className="py-2.5 px-3 text-right text-orange-600 font-mono text-xs">-{fmt(c.irpfAmt)}</td>
                    <td className="py-2.5 px-3 text-right font-black text-violet-700 font-mono">{fmt(c.liquidoNeto)}</td>
                    <td className="py-2.5 px-3 text-right text-gray-600 font-mono text-xs">{fmt(c.costeEmpresa)}</td>
                    <td className="py-2.5 px-3 text-right"><Tag color={n.estado==="pagada"?"green":"amber"}>{n.estado==="pagada"?"Pagada":"Pendiente"}</Tag></td>
                    <td className="py-2.5 px-3" onClick={e=>e.stopPropagation()}>
                      <div className="flex gap-1 justify-center">
                        <button onClick={() => onView(n)} title="Ver" className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-slate-500 hover:text-slate-900 hover:bg-slate-100 transition-colors">{Ico.eye}</button>
                        <button onClick={() => { const tw=trabajadores.find(t=>t.id===n.trabajadorId)||{}; downloadPDF(buildNominaPrintHTML(n,tw),`nomina-${n.trabajadorNombre.replace(/ /g,"-")}.pdf`); }} title="PDF" className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-sky-500 hover:text-sky-700 hover:bg-sky-50 transition-colors">{Ico.print}</button>
                        <button onClick={() => { if(confirm("¿Eliminar?")) onDelete(n.id); }} title="Eliminar" className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-rose-400 hover:text-rose-600 hover:bg-rose-50 transition-colors">{Ico.trash}</button>
                      </div>
                    </td>
                  </tr>
                );})}
              </tbody>
            </table>
          </div>
      }
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// LISTA FACTURAS
// ════════════════════════════════════════════════════════════

function ListaFacturas({ facturas, logo, onEdit, onDelete, onView, tipoFiltro, periodMode, periodValue, periodYear }) {
  const [search, setSearch] = useState("");
  const [filterAct, setFilterAct] = useState("Todas");
  const actDisp = ["Todas", ...new Set(facturas.map(f=>f.actividad))];

  const filtered = useMemo(() =>
    facturas
      .filter(f => tipoFiltro==="todas" || f.tipo===tipoFiltro)
      .filter(f => matchesPeriod(f,periodMode,periodValue,periodYear))
      .filter(f => filterAct==="Todas" || f.actividad===filterAct)
      .filter(f => !search || f.numero.toLowerCase().includes(search.toLowerCase()) || f.cliente.toLowerCase().includes(search.toLowerCase()) || (f.nif||"").toLowerCase().includes(search.toLowerCase()))
      .sort((a,b) => new Date(b.fecha)-new Date(a.fecha)),
    [facturas,tipoFiltro,filterAct,search,periodMode,periodValue,periodYear]
  );
  const tots = useMemo(() => filtered.reduce((acc,f) => {
    const t=calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo);
    if(f.tipo==="venta"){acc.ingresos+=t.totalBase;acc.ivaRep+=t.totalIVA;}else{acc.gastos+=t.totalBase;acc.ivaSop+=t.totalIVA;}
    return acc;
  },{ingresos:0,gastos:0,ivaRep:0,ivaSop:0}), [filtered]);

  return (
    <div className="space-y-4">
      <div className="flex gap-3 flex-wrap items-center">
        <input className="border rounded-xl px-4 py-2 text-sm flex-1 min-w-48 bg-white focus:ring-2 focus:ring-slate-300 outline-none" placeholder="Buscar número, cliente o NIF..." value={search} onChange={e=>setSearch(e.target.value)}/>
        <select className="border rounded-xl px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none" value={filterAct} onChange={e=>setFilterAct(e.target.value)}>{actDisp.map(a=><option key={a} value={a}>{a}</option>)}</select>
      </div>
      {filtered.length>0 && (
        <div className="flex flex-wrap gap-4 px-4 py-2.5 bg-white border border-gray-200 rounded-xl text-sm shadow-sm">
          <span className="text-gray-400 font-medium">{filtered.length} facturas · {getPeriodLabel(periodMode,periodValue,periodYear)}</span>
          {tots.ingresos>0&&<span className="text-emerald-700 font-bold">Ingresos: <span className="font-mono">{fmt(tots.ingresos)}</span></span>}
          {tots.gastos>0&&<span className="text-rose-600 font-bold">Gastos: <span className="font-mono">{fmt(tots.gastos)}</span></span>}
          {tots.ivaRep>0&&<span className="text-sky-600">IVA rep.: <span className="font-mono">{fmt(tots.ivaRep)}</span></span>}
          {tots.ivaSop>0&&<span className="text-sky-600">IVA sop.: <span className="font-mono">{fmt(tots.ivaSop)}</span></span>}
        </div>
      )}
      {filtered.length===0
        ? <div className="text-center py-20 bg-white border border-gray-100 rounded-2xl"><div className="text-5xl mb-3">📄</div><div className="text-sm font-semibold text-gray-400">Sin facturas en {getPeriodLabel(periodMode,periodValue,periodYear)}</div></div>
        : <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["Tipo","Número","Fecha","Cliente / Proveedor","Actividad","Base","IVA","Ret.","Total","Estado",""].map((h,i) => (<th key={i} className={`py-3 px-3 text-xs font-semibold text-gray-500 uppercase tracking-wide ${i<4?"text-left":"text-right"} ${i===10?"text-center":""}`}>{h}</th>))}</tr>
              </thead>
              <tbody>
                {filtered.map(f => {
                  const t=calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo);
                  const isV=f.tipo==="venta";
                  const pendiente = isV ? !f.cobrado : !f.pagado;
                  return (
                    <tr key={f.id} className={`border-t border-gray-100 hover:bg-slate-50 cursor-pointer group transition-colors ${pendiente?"bg-orange-50/20":""}`} onClick={() => onView(f)}>
                      <td className="py-2.5 px-3" onClick={e=>e.stopPropagation()}><Tag color={isV?"green":"red"}>{isV?"Venta":"Gasto"}</Tag></td>
                      <td className="py-2.5 px-3 font-mono text-xs font-black text-gray-600">
                        <div className="flex items-center gap-1">
                          {f.numero}
                          {f.documento_url && (
                            <svg title="Tiene documento adjunto" className="w-3 h-3 text-blue-400 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13"/>
                            </svg>
                          )}
                        </div>
                      </td>
                      <td className="py-2.5 px-3 text-gray-500 text-xs whitespace-nowrap">{new Date(f.fecha).toLocaleDateString("es-ES")}</td>
                      <td className="py-2.5 px-3"><div className="font-semibold text-gray-800 truncate max-w-36">{f.cliente}</div>{f.nif&&<div className="text-xs text-gray-400 font-mono">{f.nif}</div>}</td>
                      <td className="py-2.5 px-3"><Tag color="gray">{f.actividad}</Tag></td>
                      <td className="py-2.5 px-3 text-right font-semibold font-mono">{fmt(t.totalBase)}</td>
                      <td className="py-2.5 px-3 text-right text-sky-600 font-mono text-xs">{fmt(t.totalIVA)}</td>
                      <td className="py-2.5 px-3 text-right text-orange-500 font-mono text-xs">{t.totalRetencion>0?fmt(t.totalRetencion):"-"}</td>
                      <td className={`py-2.5 px-3 text-right font-black font-mono ${isV?"text-emerald-700":"text-rose-600"}`}>{fmt(t.total)}</td>
                      <td className="py-2.5 px-3 text-right"><Tag color={pendiente?"orange":"green"}>{pendiente?(isV?"Pendiente cobro":"Pendiente pago"):(isV?"Cobrada":"Pagada")}</Tag></td>
                      <td className="py-2.5 px-3" onClick={e=>e.stopPropagation()}>
                        <div className="flex gap-1 justify-center">
                          {[
                            { icon:Ico.eye,   color:"text-slate-500 hover:text-slate-900 hover:bg-slate-100", fn:()=>onView(f), title:"Ver" },
                            { icon:Ico.print, color:"text-sky-500 hover:text-sky-700 hover:bg-sky-50",       fn:()=>openPrint(buildFacturaPrintHTML(f,logo)), title:"Imprimir" },
                            { icon:Ico.pdf,   color:"text-rose-500 hover:text-rose-700 hover:bg-rose-50",    fn:()=>downloadPDF(buildFacturaPrintHTML(f,logo),`${f.numero}.pdf`), title:"Descargar PDF" },
                            { icon:Ico.down,  color:"text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50", fn:()=>downloadHTML(buildFacturaPrintHTML(f,logo),`${f.numero}.html`), title:"Descargar HTML" },
                            { icon:Ico.edit,  color:"text-amber-500 hover:text-amber-700 hover:bg-amber-50", fn:()=>onEdit(f), title:"Editar" },
                            { icon:Ico.trash, color:"text-rose-400 hover:text-rose-600 hover:bg-rose-50",    fn:()=>onDelete(f.id), title:"Eliminar" },
                          ].map(({icon,color,fn,title}) => (
                            <button key={title} onClick={fn} title={title} className={`p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-all ${color}`}>{icon}</button>
                          ))}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
      }
    </div>
  );
}

