// ════════════════════════════════════════════════════════════
// HTML IMPRIMIBLE - RESUMEN CONTABLE (mes / trimestre / año)
// ════════════════════════════════════════════════════════════
function buildResumenContablePrintHTML({ pLabel, qLabel, resF, resN, gastosTotal, ivaAPagar, pagoIRPF_F, irpf111, factP, nomiP, porActividad, periodMode, periodValue, periodYear }) {
  const now = new Date().toLocaleDateString("es-ES", { day:"2-digit", month:"long", year:"numeric" });
  const rowsFacturas = (tipo) => factP.filter(f=>f.tipo===tipo).map(f=>{
    const t = calcFactura(f.lineas, f.retencionPct, f.aplicarRecargo);
    const nombre = f.clienteNombre || f.cliente_nombre || "-";
    const nif = f.clienteNif || f.cliente_nif || "-";
    return `<tr>
      <td>${f.fecha||""}</td><td>${f.numero||""}</td>
      <td>${nombre}</td><td>${nif}</td>
      <td style="text-align:right">${fmt(t.totalBase)}</td>
      <td style="text-align:right">${fmt(t.totalIVA)}</td>
      <td style="text-align:right">${fmt(t.totalRetencion)}</td>
      <td style="text-align:right">${fmt(t.total)}</td>
    </tr>`;
  }).join("");

  const rowsNominas = nomiP.map(n=>{
    const calc = calcNomina(n);
    return `<tr>
      <td>${n.fecha||""}</td>
      <td>${n.trabajadorNombre||n.trabajador_nombre||"-"}</td>
      <td style="text-align:right">${fmt(calc.bruto)}</td>
      <td style="text-align:right">${fmt(calc.ssTrabajador)}</td>
      <td style="text-align:right">${fmt(calc.irpf)}</td>
      <td style="text-align:right">${fmt(calc.neto)}</td>
      <td style="text-align:right">${fmt(calc.ssEmpresa)}</td>
      <td style="text-align:right">${fmt(calc.costeTotal)}</td>
    </tr>`;
  }).join("");

  const actRows = porActividad.map(([act, v])=>`<tr>
    <td>${act||"Sin actividad"}</td>
    <td style="text-align:right">${fmt(v.ingresos)}</td>
    <td style="text-align:right">${fmt(v.gastos)}</td>
    <td style="text-align:right">${fmt(v.ingresos-v.gastos)}</td>
    <td style="text-align:right">${v.n}</td>
  </tr>`).join("");

  const resultado = resF.ingresos - gastosTotal;
  const css = `
    body{font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1e293b;margin:0;padding:0}
    h1{font-size:18px;font-weight:800;margin:0 0 2px}
    h2{font-size:13px;font-weight:700;margin:18px 0 6px;color:#0f172a;border-bottom:2px solid #e2e8f0;padding-bottom:4px}
    h3{font-size:11px;font-weight:700;margin:12px 0 4px;color:#475569}
    table{width:100%;border-collapse:collapse;margin-bottom:8px;font-size:10px}
    th{background:#0f172a;color:#fff;padding:5px 7px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.04em}
    td{padding:4px 7px;border-bottom:1px solid #f1f5f9}
    tr:nth-child(even) td{background:#f8fafc}
    .kpi-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px}
    .kpi{background:#f1f5f9;border-radius:8px;padding:10px 12px}
    .kpi-val{font-size:15px;font-weight:800;color:#0f172a}
    .kpi-lbl{font-size:9px;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-top:2px}
    .kpi.green .kpi-val{color:#059669} .kpi.red .kpi-val{color:#dc2626} .kpi.blue .kpi-val{color:#2563eb} .kpi.amber .kpi-val{color:#d97706}
    .fis-box{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px}
    .fis{background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:10px 12px}
    .fis-title{font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;margin-bottom:4px}
    .fis-val{font-size:13px;font-weight:800;color:#0f172a}
    .fis-sub{font-size:9px;color:#94a3b8;margin-top:2px}
    .header-bar{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:16px;padding-bottom:12px;border-bottom:3px solid #0f172a}
    .badge{display:inline-block;background:#0f172a;color:#fff;border-radius:4px;padding:2px 8px;font-size:9px;font-weight:700;letter-spacing:.06em;margin-top:4px}
    .total-row td{font-weight:700;background:#f1f5f9!important;border-top:2px solid #cbd5e1}
    @media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}@page{margin:12mm 14mm;size:A4}}
  `;

  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Resumen Contable ${pLabel}</title>
  <style>${css}</style></head><body>
  <div class="header-bar">
    <div>
      <h1>Resumen Contable</h1>
      <div class="badge">${pLabel}</div>
    </div>
    <div style="text-align:right;font-size:10px;color:#64748b">Generado el ${now}</div>
  </div>

  <div class="kpi-grid">
    <div class="kpi green"><div class="kpi-val">${fmt(resF.ingresos)}</div><div class="kpi-lbl">Ingresos (base)</div></div>
    <div class="kpi red"><div class="kpi-val">${fmt(resF.gastos)}</div><div class="kpi-lbl">Gastos facturación</div></div>
    <div class="kpi blue"><div class="kpi-val">${fmt(resN.totalCoste)}</div><div class="kpi-lbl">Coste nóminas</div></div>
    <div class="kpi ${resultado>=0?"green":"red"}"><div class="kpi-val">${fmt(resultado)}</div><div class="kpi-lbl">Resultado real</div></div>
  </div>

  <h2>Obligaciones fiscales estimadas - ${qLabel}</h2>
  <div class="fis-box">
    <div class="fis"><div class="fis-title">Mod. 303 - IVA a ingresar</div><div class="fis-val">${fmt(ivaAPagar)}</div><div class="fis-sub">IVA rep. ${fmt(resF.ivaRep)} - IVA sop. ${fmt(resF.ivaSop)}</div></div>
    <div class="fis"><div class="fis-title">Mod. 130 - IRPF estimación directa</div><div class="fis-val">${fmt(pagoIRPF_F)}</div><div class="fis-sub">20% sobre rendimiento neto</div></div>
    <div class="fis"><div class="fis-title">Mod. 111 - IRPF retenciones</div><div class="fis-val">${fmt(irpf111)}</div><div class="fis-sub">Nóminas + profesionales externos</div></div>
  </div>

  ${porActividad.length > 0 ? `
  <h2>Resultados por actividad</h2>
  <table><thead><tr><th>Actividad</th><th>Ingresos</th><th>Gastos</th><th>Resultado</th><th>Docs</th></tr></thead>
  <tbody>${actRows}</tbody></table>` : ""}

  ${factP.filter(f=>f.tipo==="venta").length > 0 ? `
  <h2>Facturas emitidas (${factP.filter(f=>f.tipo==="venta").length})</h2>
  <table><thead><tr><th>Fecha</th><th>Número</th><th>Cliente</th><th>NIF</th><th>Base</th><th>IVA</th><th>Retención</th><th>Total</th></tr></thead>
  <tbody>${rowsFacturas("venta")}
  <tr class="total-row"><td colspan="4">TOTAL</td>
    <td style="text-align:right">${fmt(resF.ingresos)}</td>
    <td style="text-align:right">${fmt(resF.ivaRep)}</td>
    <td style="text-align:right">${fmt(resF.retencionesSop)}</td>
    <td style="text-align:right">${fmt(resF.ingresos+resF.ivaRep-resF.retencionesSop)}</td>
  </tr></tbody></table>` : ""}

  ${factP.filter(f=>f.tipo==="gasto").length > 0 ? `
  <h2>Facturas recibidas / gastos (${factP.filter(f=>f.tipo==="gasto").length})</h2>
  <table><thead><tr><th>Fecha</th><th>Número</th><th>Proveedor</th><th>NIF</th><th>Base</th><th>IVA</th><th>Retención</th><th>Total</th></tr></thead>
  <tbody>${rowsFacturas("gasto")}
  <tr class="total-row"><td colspan="4">TOTAL</td>
    <td style="text-align:right">${fmt(resF.gastos)}</td>
    <td style="text-align:right">${fmt(resF.ivaSop)}</td>
    <td style="text-align:right">${fmt(resF.retencionesRep)}</td>
    <td style="text-align:right">${fmt(resF.gastos+resF.ivaSop-resF.retencionesRep)}</td>
  </tr></tbody></table>` : ""}

  ${nomiP.length > 0 ? `
  <h2>Nóminas (${nomiP.length})</h2>
  <table><thead><tr><th>Fecha</th><th>Trabajador</th><th>Bruto</th><th>SS Trab.</th><th>IRPF</th><th>Neto</th><th>SS Empresa</th><th>Coste total</th></tr></thead>
  <tbody>${rowsNominas}
  <tr class="total-row"><td colspan="2">TOTAL</td>
    <td style="text-align:right">${fmt(resN.totalBruto)}</td>
    <td style="text-align:right">${fmt(resN.totalSSTrab)}</td>
    <td style="text-align:right">${fmt(resN.totalIRPF)}</td>
    <td style="text-align:right">${fmt(resN.totalNeto)}</td>
    <td style="text-align:right">${fmt(resN.totalSSEmp)}</td>
    <td style="text-align:right">${fmt(resN.totalCoste)}</td>
  </tr></tbody></table>` : ""}

  <div style="margin-top:24px;padding-top:10px;border-top:1px solid #e2e8f0;font-size:9px;color:#94a3b8;text-align:center">
    ContaAuto · Documento generado automáticamente · Solo orientativo, no sustituye asesoría fiscal
  </div>
  </body></html>`;
}

function Dashboard({ facturas, nominas, trabajadores, periodMode, periodValue, periodYear }) {
  const factP = useMemo(() => facturas.filter(f => matchesPeriod(f,periodMode,periodValue,periodYear)), [facturas,periodMode,periodValue,periodYear]);
  const nomiP = useMemo(() => nominas.filter(n => matchesPeriod(n,periodMode,periodValue,periodYear)), [nominas,periodMode,periodValue,periodYear]);
  const resF  = useMemo(() => summarizeFacturas(factP), [factP]);
  const resN  = useMemo(() => summarizeNominas(nomiP), [nomiP]);
  const pLabel = getPeriodLabel(periodMode,periodValue,periodYear);

  // Pendientes globales (sin filtro de período)
  const pendCobro  = facturas.filter(f=>f.tipo==="venta"&&!f.cobrado).reduce((s,f)=>s+calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo).total,0);
  const pendPago   = facturas.filter(f=>f.tipo==="gasto"&&!f.pagado).reduce((s,f)=>s+calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo).total,0);
  const nPendC     = facturas.filter(f=>f.tipo==="venta"&&!f.cobrado).length;
  const nPendP     = facturas.filter(f=>f.tipo==="gasto"&&!f.pagado).length;

  const gastosTotal = resF.gastos + resN.totalCoste;

  const qIdx  = periodMode==="trimestre" ? periodValue : Math.floor(new Date().getMonth()/3);
  const factsQ = useMemo(() => facturas.filter(f=>{const d=new Date(f.fecha);return Math.floor(d.getMonth()/3)===qIdx&&d.getFullYear()===periodYear;}), [facturas,qIdx,periodYear]);
  const nomiQ  = useMemo(() => nominas.filter(n=>{const d=new Date(n.fecha);return Math.floor(d.getMonth()/3)===qIdx&&d.getFullYear()===periodYear;}), [nominas,qIdx,periodYear]);
  const qF     = useMemo(() => summarizeFacturas(factsQ), [factsQ]);
  const qN     = useMemo(() => summarizeNominas(nomiQ), [nomiQ]);
  const ivaAPagar   = qF.ivaRep - qF.ivaSop;
  // Mod. 130: estimación directa simplificada (art. 110 RIRPF)
  // Rendimiento neto = Ingresos - Gastos deducibles - Costes laborales
  // Base: 20% sobre rendimiento neto acumulado en el trimestre
  // Minoración: retenciones soportadas en ventas (IRPF que clientes retienen)
  const rendNeto    = Math.max(0, qF.beneficio - qN.totalCoste);
  const pagoIRPF_F  = Math.max(0, rendNeto * 0.20 - qF.retencionesSop);
  // Mod. 111: IRPF retenciones practicadas
  // Trabajadores (nóminas) + profesionales autónomos pagados con retención
  const irpf111     = qN.totalIRPF + qF.retencionesRep;
  const qLabel      = `${Q_NAMES[qIdx]} ${periodYear}`;

  const porActividad = useMemo(() => {
    const map={};
    factP.forEach(f=>{if(!map[f.actividad])map[f.actividad]={ingresos:0,gastos:0,n:0};const t=calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo);if(f.tipo==="venta")map[f.actividad].ingresos+=t.totalBase;else map[f.actividad].gastos+=t.totalBase;map[f.actividad].n++;});
    return Object.entries(map).sort((a,b)=>(b[1].ingresos+b[1].gastos)-(a[1].ingresos+a[1].gastos));
  }, [factP]);
  const maxBar = Math.max(...porActividad.map(([,v])=>v.ingresos+v.gastos),1);

  const handlePrintResumen = () => {
    const html = buildResumenContablePrintHTML({ pLabel, qLabel, resF, resN, gastosTotal, ivaAPagar, pagoIRPF_F, irpf111, factP, nomiP, porActividad, periodMode, periodValue, periodYear });
    openPrint(html);
  };
  const handlePDFResumen = () => {
    const html = buildResumenContablePrintHTML({ pLabel, qLabel, resF, resN, gastosTotal, ivaAPagar, pagoIRPF_F, irpf111, factP, nomiP, porActividad, periodMode, periodValue, periodYear });
    downloadPDF(html, `resumen-contable-${pLabel.replace(/ /g,"-")}.pdf`);
  };

  return (
    <div className="space-y-8">
      {/* Botones imprimir / PDF resumen */}
      <div className="flex justify-end gap-2">
        <button onClick={handlePrintResumen}
          className="flex items-center gap-1.5 text-xs font-semibold px-4 py-2 rounded-xl border border-slate-300 bg-white hover:bg-slate-50 text-slate-700 transition-colors shadow-sm">
          {Ico.print} Imprimir resumen
        </button>
        <button onClick={handlePDFResumen}
          className="flex items-center gap-1.5 text-xs font-semibold px-4 py-2 rounded-xl bg-slate-900 hover:bg-slate-700 text-white transition-colors shadow-sm">
          {Ico.pdf} Descargar PDF
        </button>
      </div>
      <div>
        <Divider label={`Resumen consolidado - ${pLabel}`}/>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <KPI label="Ingresos (base)" value={fmt(resF.ingresos)} sub={`${factP.filter(f=>f.tipo==="venta").length} ventas`} tint="green"/>
          <KPI label="Gastos facturación" value={fmt(resF.gastos)} sub={`${factP.filter(f=>f.tipo==="gasto").length} gastos`} tint="red"/>
          <KPI label="Coste nóminas" value={fmt(resN.totalCoste)} sub={`${nomiP.length} nóminas`} tint="violet"/>
          <KPI label="Resultado real" value={fmt(resF.ingresos - gastosTotal)} sub="Ingresos - gastos - nóminas" accent/>
        </div>
      </div>

      {/* Saldos pendientes - resumen en dashboard */}
      {(nPendC > 0 || nPendP > 0) && (
        <div>
          <Divider label="Saldos pendientes (global)"/>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <KPI label="Pendiente cobro" value={fmt(pendCobro)} tint="orange" sub={`${nPendC} factura${nPendC!==1?"s":""} sin cobrar`}/>
            <KPI label="Pendiente pago" value={fmt(pendPago)} tint="red" sub={`${nPendP} factura${nPendP!==1?"s":""} sin pagar`}/>
            <KPI label="Saldo neto pendiente" value={fmt(pendCobro-pendPago)} sub="Cobros - pagos pendientes"/>
            <KPI label="Trabajadores activos" value={String(trabajadores.filter(t=>t.activo).length)} sub={`${trabajadores.length} registrados`} tint="violet"/>
          </div>
        </div>
      )}

      {nomiP.length>0 && (
        <div>
          <Divider label={`Costes laborales - ${pLabel}`}/>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <KPI label="Bruto nóminas" value={fmt(resN.totalBruto)}/>
            <KPI label="Neto a pagar" value={fmt(resN.totalNeto)} sub="Líquido total trabajadores"/>
            <KPI label="SS empresa" value={fmt(resN.totalSSEmp)} tint="amber" sub="A ingresar TGSS"/>
            <KPI label="IRPF retenido" value={fmt(resN.totalIRPF)} sub="Mod. 111"/>
          </div>
        </div>
      )}

      <div>
        <Divider label={`Previsión AEAT - ${qLabel}`}/>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
          {/* MOD. 303 - IVA trimestral (art. 71 LIVA) */}
          <div className="bg-amber-50 border border-amber-200 rounded-xl p-5">
            <div className="flex items-center gap-2 mb-1">
              <span className="bg-amber-600 text-white text-xs font-black px-2 py-0.5 rounded">MOD. 303</span>
              <span className="text-sm font-bold text-amber-900">IVA trimestral</span>
            </div>
            <p className="text-xs text-amber-700 mb-3">Autoliquidación IVA · art. 71 LIVA</p>
            <div className="space-y-1.5 text-sm">
              <div className="flex justify-between"><span className="text-gray-600">IVA repercutido (ventas)</span><span className="font-semibold font-mono text-emerald-700">+{fmt(qF.ivaRep)}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">IVA soportado (gastos)</span><span className="font-semibold font-mono text-rose-600">-{fmt(qF.ivaSop)}</span></div>
              {ivaAPagar < 0 && <div className="text-xs text-indigo-600 mt-1">Crédito pendiente de compensar en trimestres siguientes o solicitar devolución (4T)</div>}
              <div className="flex justify-between font-black border-t border-amber-300 pt-2 text-base">
                <span className="text-amber-900">{ivaAPagar >= 0 ? "Cuota a ingresar" : "A compensar"}</span>
                <span className="text-amber-900 font-mono">{ivaAPagar >= 0 ? fmt(ivaAPagar) : `${fmt(Math.abs(ivaAPagar))}`}</span>
              </div>
            </div>
          </div>

          {/* MOD. 130 - Pago fraccionado IRPF (art. 110 RIRPF) */}
          <div className="bg-indigo-50 border border-indigo-200 rounded-xl p-5">
            <div className="flex items-center gap-2 mb-1">
              <span className="bg-indigo-600 text-white text-xs font-black px-2 py-0.5 rounded">MOD. 130</span>
              <span className="text-sm font-bold text-indigo-900">IRPF fraccionado</span>
            </div>
            <p className="text-xs text-indigo-700 mb-3">Estimación directa simplificada · art. 110 RIRPF</p>
            <div className="space-y-1.5 text-sm">
              <div className="flex justify-between"><span className="text-gray-600">Ingresos netos</span><span className="font-semibold font-mono">{fmt(qF.ingresos)}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">Gastos deducibles</span><span className="font-semibold font-mono text-rose-600">-{fmt(qF.gastos + qN.totalCoste)}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">Rendimiento neto</span><span className="font-semibold font-mono">{fmt(rendNeto)}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">20% s/ rendimiento</span><span className="font-semibold font-mono">{fmt(rendNeto * 0.20)}</span></div>
              {qF.retencionesSop > 0 && <div className="flex justify-between"><span className="text-gray-600">Retenciones soportadas</span><span className="font-semibold font-mono text-rose-600">-{fmt(qF.retencionesSop)}</span></div>}
              {pagoIRPF_F === 0 && rendNeto > 0 && <div className="text-xs text-indigo-600 mt-1">Cuota cero: retenciones cubren el pago fraccionado</div>}
              <div className="flex justify-between font-black border-t border-indigo-300 pt-2 text-base">
                <span className="text-indigo-900">Pago trimestral</span>
                <span className="text-indigo-900 font-mono">{fmt(pagoIRPF_F)}</span>
              </div>
            </div>
          </div>

          {/* MOD. 111 - IRPF retenciones (art. 76 RIRPF) */}
          <div className="bg-violet-50 border border-violet-200 rounded-xl p-5">
            <div className="flex items-center gap-2 mb-1">
              <span className="bg-violet-600 text-white text-xs font-black px-2 py-0.5 rounded">MOD. 111</span>
              <span className="text-sm font-bold text-violet-900">IRPF</span>
            </div>
            <p className="text-xs text-violet-700 mb-3">Retenciones e ingresos a cuenta · art. 76 RIRPF</p>
            <div className="space-y-1.5 text-sm">
              {qN.totalIRPF > 0 && <div className="flex justify-between"><span className="text-gray-600">IRPF trabajadores</span><span className="font-semibold font-mono">{fmt(qN.totalIRPF)}</span></div>}
              {qF.retencionesRep > 0 && <div className="flex justify-between"><span className="text-gray-600">IRPF profesionales</span><span className="font-semibold font-mono">{fmt(qF.retencionesRep)}</span></div>}
              {irpf111 === 0 && <div className="text-xs text-violet-600">Sin retenciones practicadas este trimestre</div>}
              {qN.totalSSTrab + qN.totalSSEmp > 0 && (
                <div className="flex justify-between text-gray-500 text-xs pt-1 border-t border-violet-200"><span>SS total (TGSS)</span><span className="font-mono">{fmt(qN.totalSSTrab + qN.totalSSEmp)}</span></div>
              )}
              <div className="flex justify-between font-black border-t border-violet-300 pt-2 text-base">
                <span className="text-violet-900">A ingresar</span>
                <span className="text-violet-900 font-mono">{fmt(irpf111)}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Nota legal */}
        <div className="mb-4 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs text-slate-500 leading-relaxed">
          Las cifras son estimadas para el {qLabel}. El Mod. 130 aplica a estimación directa (normal o simplificada); si tributas por módulos, no procede. Las retenciones soportadas en ventas minoran el Mod. 130 conforme al art. 110.3 RIRPF. Consulta siempre con tu asesor fiscal antes de presentar.
        </div>

        <KPI label={`Obligaciones fiscales estimadas · ${qLabel}`}
          value={fmt(Math.max(0, ivaAPagar) + pagoIRPF_F + irpf111)} accent
          sub={`Mod. 303: ${fmt(Math.max(0,ivaAPagar))} · Mod. 130: ${fmt(pagoIRPF_F)} · Mod. 111: ${fmt(irpf111)} · TGSS: ${fmt(qN.totalSSTrab+qN.totalSSEmp)}`}/>
      </div>

      {porActividad.length>0 && (
        <div>
          <Divider label={`Por actividad - ${pLabel}`}/>
          <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["Actividad","Docs.","Ingresos","Gastos","Resultado",""].map((h,i)=>(<th key={i} className={`py-3 px-4 text-xs font-semibold text-gray-500 uppercase tracking-wide ${i===0?"text-left":"text-right"} ${i===5?"w-28":""}`}>{h}</th>))}</tr>
              </thead>
              <tbody>
                {porActividad.map(([act,v]) => {
                  const r=v.ingresos-v.gastos;
                  return (<tr key={act} className="border-t border-gray-100 hover:bg-gray-50">
                    <td className="py-3 px-4 font-semibold text-gray-800">{act}</td>
                    <td className="py-3 px-4 text-right text-gray-400">{v.n}</td>
                    <td className="py-3 px-4 text-right font-semibold text-emerald-700 font-mono">{fmt(v.ingresos)}</td>
                    <td className="py-3 px-4 text-right font-semibold text-rose-600 font-mono">{fmt(v.gastos)}</td>
                    <td className={`py-3 px-4 text-right font-black font-mono ${r>=0?"text-sky-700":"text-orange-600"}`}>{fmt(r)}</td>
                    <td className="py-3 px-4"><div className="bg-gray-200 rounded-full h-1.5"><div className="bg-slate-700 h-1.5 rounded-full" style={{width:`${Math.round(((v.ingresos+v.gastos)/maxBar)*100)}%`}}/></div></td>
                  </tr>);
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

