function GestionActividades({ actividades, setActividades }) {
  const [nueva, setNueva] = useState("");
  return (
    <div className="max-w-xl">
      <Divider label="Actividades del negocio"/>
      <p className="text-sm text-gray-500 mb-5">Clasifican cada factura. Las predeterminadas no se eliminan.</p>
      <div className="space-y-2 mb-6">
        {actividades.map(a => (
          <div key={a} className="flex items-center justify-between bg-white border border-gray-200 rounded-xl px-4 py-3">
            <div className="flex items-center gap-3"><div className="w-2 h-2 rounded-full bg-slate-300"/><span className="text-sm font-semibold text-gray-800">{a}</span></div>
            {ACTS_INIT.includes(a)
              ? <span className="text-xs text-gray-300">Predeterminada</span>
              : <button onClick={() => { if(confirm(`¿Eliminar "${a}"?`)) setActividades(p=>p.filter(x=>x!==a)); }} className="text-xs text-rose-400 hover:text-rose-600 font-semibold">Eliminar</button>
            }
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input className="border rounded-xl px-4 py-2.5 text-sm flex-1 focus:ring-2 focus:ring-slate-300 outline-none" placeholder="Nueva actividad..." value={nueva} onChange={e=>setNueva(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"){const t=nueva.trim();if(t&&!actividades.includes(t)){setActividades(p=>[...p,t]);setNueva("");}}}}/>
        <button onClick={() => {const t=nueva.trim();if(t&&!actividades.includes(t)){setActividades(p=>[...p,t]);setNueva("");}}} className="bg-slate-900 hover:bg-slate-700 text-white px-5 py-2.5 rounded-xl text-sm font-bold">Añadir</button>
      </div>
    </div>
  );
}

