// ════════════════════════════════════════════════════════════
// VISTA EXTRACTO BANCARIO + INSPECTOR FISCAL IA
// ════════════════════════════════════════════════════════════

const MESES_ES = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];

// ── Parser universal de extractos bancarios españoles ──────
function parsearExtracto(raw) {
  const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
  const movs  = [];
  // detectar cabecera (primera línea con letras sin importe)
  let skipFirst = false;
  if (lines.length > 1) {
    const primero = lines[0].replace(/"/g,"");
    if (!/[0-9]/.test(primero) || /fecha|concepto|importe|saldo|date|amount|valor/i.test(primero)) skipFirst = true;
  }
  for (let li = skipFirst ? 1 : 0; li < lines.length; li++) {
    const raw = lines[li];
    let cols = raw.includes(";") ? raw.split(";") : raw.includes("\t") ? raw.split("\t") : raw.split(",");
    cols = cols.map(c => c.replace(/^"|"$/g,"").trim());
    if (cols.length < 2) continue;
    let fecha = "", concepto = "", importe = null, saldo = null;
    for (const v of cols) {
      // fecha
      if (/^\d{1,2}[\/\-\.]\d{1,2}[\/\-\.]\d{2,4}$/.test(v) || /^\d{4}[\/\-]\d{2}[\/\-]\d{2}$/.test(v)) { if (!fecha) fecha = v; continue; }
      // importe: número con coma o punto decimal, posible signo, posible separador de miles
      const n = parseFloat(v.replace(/\./g,"").replace(",",".").replace(/\s/g,""));
      if (!isNaN(n) && v !== "" && /[\d,\.]/.test(v)) {
        if (importe === null) importe = n;
        else if (saldo === null) saldo = n;
        continue;
      }
      if (v.length > 1) concepto = concepto ? concepto + " " + v : v;
    }
    if (importe !== null && Math.abs(importe) > 0) {
      movs.push({ fecha, concepto: concepto || "Sin descripción", importe, saldo });
    }
  }
  return movs;
}

// ── Categorización automática de movimientos ──────────────
const CATS_BANCO = [
  { id:"seguridad_social", label:"Seguridad Social / TGSS", color:"violet",  patterns:[/tgss|seguridad social|cuota autonomo|reta|mutua|coleg/i] },
  { id:"hacienda",         label:"AEAT / Hacienda",         color:"rose",    patterns:[/aeat|agencia tributaria|mod\s*\d{3}|hacienda|irpf|iva\s+trimestral|modelo/i] },
  { id:"suministros",      label:"Suministros (luz/agua/gas)",color:"amber", patterns:[/endesa|iberdrola|naturgy|gas natural|repsol|acciona|e\.on|r\s*energia|hidroelectrica|enel|sevillana|hidrocantabrico|aqualia|aguas|canal.*isabel|agbar/i] },
  { id:"telecomunicaciones",label:"Telecomunicaciones",     color:"sky",     patterns:[/movistar|vodafone|orange|masmovil|digi|yoigo|jazztel|fibra|telefonica|sim\s*card/i] },
  { id:"nominas",          label:"Nóminas / Personal",      color:"indigo",  patterns:[/nomina|salario|haberes|trabajador|empleado/i] },
  { id:"alquiler",         label:"Alquiler",                color:"teal",    patterns:[/alquiler|arrendamiento|inquilino|propietario|mensualidad piso|local/i] },
  { id:"financiero",       label:"Financiero / Bancario",   color:"slate",   patterns:[/cuota prestamo|cuota hipoteca|leasing|renting|interes|comision banco|mantenimiento cuenta|tae|tin|amortiz/i] },
  { id:"seguros",          label:"Seguros",                 color:"cyan",    patterns:[/seguro|prima|aseguradora|mapfre|axa|allianz|zurich|sanitas|adeslas|mutua.*madrilena/i] },
  { id:"ingresos_clientes",label:"Ingresos clientes",       color:"emerald", patterns:[/transferencia recibida|abono|ingreso|cobro factura|honorarios recibidos/i] },
  { id:"proveedores",      label:"Proveedores / Compras",   color:"orange",  patterns:[/proveedor|compra|suministro|material|factura proveedor|amazon|aliexpress/i] },
  { id:"autonomo_gastos",  label:"Gastos profesionales",    color:"purple",  patterns:[/software|licencia|suscripcion|herramienta|formacion|curso|colegio.*profesional|asociacion/i] },
  { id:"tarjeta",          label:"Tarjeta / TPV",           color:"pink",    patterns:[/visa|mastercard|tarjeta|tpv|pago.*movil|bizum recibido|pago.*online/i] },
  { id:"otros",            label:"Otros",                   color:"gray",    patterns:[/.*/] },
];

function categorizarMov(mov) {
  for (const cat of CATS_BANCO) {
    if (cat.patterns.some(rx => rx.test(mov.concepto))) return cat;
  }
  return CATS_BANCO[CATS_BANCO.length - 1];
}

// ── Helpers de render ─────────────────────────────────────
function BadgeCategoria({ cat, small }) {
  const COLORS = {
    violet:"bg-violet-100 text-violet-700", rose:"bg-rose-100 text-rose-700",
    amber:"bg-amber-100 text-amber-700",   sky:"bg-sky-100 text-sky-700",
    indigo:"bg-indigo-100 text-indigo-700",teal:"bg-teal-100 text-teal-700",
    slate:"bg-slate-100 text-slate-700",   cyan:"bg-cyan-100 text-cyan-700",
    emerald:"bg-emerald-100 text-emerald-700", orange:"bg-orange-100 text-orange-700",
    purple:"bg-purple-100 text-purple-700", pink:"bg-pink-100 text-pink-700",
    gray:"bg-gray-100 text-gray-600",
  };
  return <span className={`inline-block font-bold rounded-full ${small?"text-xs px-2 py-0.5":"text-xs px-2.5 py-1"} ${COLORS[cat.color]||COLORS.gray}`}>{cat.label}</span>;
}

// ── Tabla de movimientos con categorías ───────────────────
function TablaMovimientosV2({ movs }) {
  const [filtro,  setFiltro]  = useState("todos");
  const [busca,   setBusca]   = useState("");
  const [catFilt, setCatFilt] = useState("todas");

  const cats = useMemo(() => {
    const set = new Set(movs.map(m => categorizarMov(m).id));
    return CATS_BANCO.filter(c => set.has(c.id));
  }, [movs]);

  const vis = movs.filter(m => {
    if (filtro === "entradas" && m.importe <= 0) return false;
    if (filtro === "salidas"  && m.importe >= 0) return false;
    if (busca && !m.concepto.toLowerCase().includes(busca.toLowerCase())) return false;
    if (catFilt !== "todas" && categorizarMov(m).id !== catFilt) return false;
    return true;
  });

  return (
    <div className="space-y-3">
      <div className="flex flex-wrap gap-2 items-center">
        <input value={busca} onChange={e => setBusca(e.target.value)} placeholder="Buscar concepto..."
          className="flex-1 min-w-36 text-sm border border-gray-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-sky-400"/>
        <div className="flex gap-1">
          {["todos","entradas","salidas"].map(f => (
            <button key={f} onClick={() => setFiltro(f)}
              className={`text-xs font-bold px-3 py-2 rounded-lg border capitalize transition-colors ${filtro===f?"bg-slate-900 text-white border-slate-900":"bg-white text-gray-600 border-gray-200 hover:border-slate-400"}`}>
              {f}
            </button>
          ))}
        </div>
        <select value={catFilt} onChange={e => setCatFilt(e.target.value)}
          className="text-xs border border-gray-200 rounded-lg px-2 py-2 focus:outline-none focus:ring-2 focus:ring-sky-400 bg-white">
          <option value="todas">Todas las categorías</option>
          {cats.map(c => <option key={c.id} value={c.id}>{c.label}</option>)}
        </select>
      </div>

      <div className="bg-white border border-gray-200 rounded-xl overflow-hidden">
        <div className="max-h-80 overflow-y-auto">
          <table className="w-full text-sm">
            <thead className="bg-gray-50 border-b border-gray-200 sticky top-0">
              <tr>
                <th className="text-left px-4 py-2.5 text-xs font-bold text-gray-500 uppercase tracking-wide w-24">Fecha</th>
                <th className="text-left px-4 py-2.5 text-xs font-bold text-gray-500 uppercase tracking-wide">Concepto</th>
                <th className="text-left px-4 py-2.5 text-xs font-bold text-gray-500 uppercase tracking-wide hidden md:table-cell">Categoría</th>
                <th className="text-right px-4 py-2.5 text-xs font-bold text-gray-500 uppercase tracking-wide w-28">Importe</th>
              </tr>
            </thead>
            <tbody>
              {vis.length === 0 && (
                <tr><td colSpan={4} className="text-center py-10 text-gray-400 text-sm">Sin movimientos para este filtro</td></tr>
              )}
              {vis.map((m, i) => {
                const cat = categorizarMov(m);
                return (
                  <tr key={i} className="border-b border-gray-50 hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-2.5 text-gray-400 text-xs font-mono whitespace-nowrap">{m.fecha || "—"}</td>
                    <td className="px-4 py-2.5 text-gray-700 max-w-xs">
                      <div className="truncate font-medium">{m.concepto}</div>
                    </td>
                    <td className="px-4 py-2.5 hidden md:table-cell">
                      <BadgeCategoria cat={cat} small/>
                    </td>
                    <td className={`px-4 py-2.5 text-right font-mono font-bold text-sm whitespace-nowrap ${m.importe >= 0 ? "text-emerald-600" : "text-rose-600"}`}>
                      {m.importe >= 0 ? "+" : ""}{m.importe.toFixed(2).replace(".", ",")} €
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <div className="px-4 py-2 bg-gray-50 border-t border-gray-100 text-xs text-gray-400 flex justify-between">
          <span>{vis.length} de {movs.length} movimientos</span>
          <span className="font-mono font-bold text-gray-600">
            {vis.reduce((s,m)=>s+m.importe,0) >= 0 ? "+" : ""}{vis.reduce((s,m)=>s+m.importe,0).toFixed(2).replace(".",",")} €
          </span>
        </div>
      </div>
    </div>
  );
}

// ── Resumen con gráfico de categorías ────────────────────
function ResumenMovimientosV2({ movs }) {
  const ingresos  = movs.filter(m => m.importe > 0).reduce((s,m) => s + m.importe, 0);
  const gastos    = movs.filter(m => m.importe < 0).reduce((s,m) => s + Math.abs(m.importe), 0);
  const saldo     = movs.reduce((s,m) => s + m.importe, 0);

  // Agrupar gastos por categoría
  const porCat = {};
  movs.filter(m => m.importe < 0).forEach(m => {
    const cat = categorizarMov(m);
    if (!porCat[cat.id]) porCat[cat.id] = { cat, total: 0, n: 0 };
    porCat[cat.id].total += Math.abs(m.importe);
    porCat[cat.id].n++;
  });
  const catOrdenadas = Object.values(porCat).sort((a,b) => b.total - a.total);
  const maxCat = catOrdenadas[0]?.total || 1;

  const top5gasto = [...movs].filter(m => m.importe < 0).sort((a,b) => a.importe - b.importe).slice(0,6);

  return (
    <div className="space-y-5">
      {/* KPIs principales */}
      <div className="grid grid-cols-3 gap-3">
        <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4 text-center">
          <div className="text-xs font-bold text-emerald-600 uppercase tracking-wide mb-1">Entradas</div>
          <div className="text-2xl font-black text-emerald-700 font-mono">{ingresos.toFixed(2).replace(".",",")} €</div>
          <div className="text-xs text-emerald-500 mt-0.5">{movs.filter(m => m.importe > 0).length} movimientos</div>
        </div>
        <div className="bg-rose-50 border border-rose-200 rounded-xl p-4 text-center">
          <div className="text-xs font-bold text-rose-600 uppercase tracking-wide mb-1">Salidas</div>
          <div className="text-2xl font-black text-rose-700 font-mono">{gastos.toFixed(2).replace(".",",")} €</div>
          <div className="text-xs text-rose-500 mt-0.5">{movs.filter(m => m.importe < 0).length} movimientos</div>
        </div>
        <div className={`border rounded-xl p-4 text-center ${saldo >= 0 ? "bg-sky-50 border-sky-200" : "bg-amber-50 border-amber-200"}`}>
          <div className={`text-xs font-bold uppercase tracking-wide mb-1 ${saldo >= 0 ? "text-sky-600" : "text-amber-600"}`}>Saldo neto</div>
          <div className={`text-2xl font-black font-mono ${saldo >= 0 ? "text-sky-700" : "text-amber-700"}`}>{saldo >= 0 ? "+" : ""}{saldo.toFixed(2).replace(".",",")} €</div>
          <div className={`text-xs mt-0.5 ${saldo >= 0 ? "text-sky-500" : "text-amber-500"}`}>{movs.length} movimientos totales</div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
        {/* Desglose por categoría */}
        {catOrdenadas.length > 0 && (
          <div className="bg-white border border-gray-200 rounded-xl overflow-hidden">
            <div className="px-4 py-3 border-b border-gray-100 text-xs font-bold text-gray-500 uppercase tracking-widest">Gasto por categoría</div>
            <div className="p-4 space-y-2.5">
              {catOrdenadas.map(({cat, total, n}) => (
                <div key={cat.id}>
                  <div className="flex justify-between items-center mb-1">
                    <BadgeCategoria cat={cat} small/>
                    <span className="font-mono font-bold text-sm text-gray-700">{total.toFixed(2).replace(".",",")} €
                      <span className="text-xs font-normal text-gray-400 ml-1">({n})</span>
                    </span>
                  </div>
                  <div className="h-1.5 bg-gray-100 rounded-full overflow-hidden">
                    <div className="h-full bg-rose-400 rounded-full transition-all" style={{width: `${(total/maxCat)*100}%`}}/>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Top gastos individuales */}
        {top5gasto.length > 0 && (
          <div className="bg-white border border-gray-200 rounded-xl overflow-hidden">
            <div className="px-4 py-3 border-b border-gray-100 text-xs font-bold text-gray-500 uppercase tracking-widest">Mayores salidas individuales</div>
            <div className="divide-y divide-gray-50">
              {top5gasto.map((m,i) => (
                <div key={i} className="flex items-center gap-3 px-4 py-2.5">
                  <div className="w-6 h-6 bg-rose-100 rounded-full flex items-center justify-center text-rose-600 text-xs font-black flex-shrink-0">{i+1}</div>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium text-gray-800 truncate">{m.concepto}</div>
                    <div className="flex items-center gap-2 mt-0.5">
                      <BadgeCategoria cat={categorizarMov(m)} small/>
                      {m.fecha && <span className="text-xs text-gray-400">{m.fecha}</span>}
                    </div>
                  </div>
                  <div className="font-mono font-bold text-rose-600 text-sm flex-shrink-0">{Math.abs(m.importe).toFixed(2).replace(".",",")} €</div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Panel renderizador del informe IA ─────────────────────
function InformeInspector({ analisis, mes, anio, onExport }) {
  const secciones = [];
  let seccionActual = null;
  const lineas = analisis.split("\n");

  for (const raw of lineas) {
    const l = raw.trim();
    if (!l) continue;

    if (l.startsWith("# ")) {
      if (seccionActual) secciones.push(seccionActual);
      seccionActual = { titulo: l.replace(/^#\s+/, ""), nivel: 1, contenido: [] };
    } else if (l.startsWith("## ")) {
      if (seccionActual) secciones.push(seccionActual);
      seccionActual = { titulo: l.replace(/^##\s+/, ""), nivel: 2, contenido: [] };
    } else {
      if (!seccionActual) seccionActual = { titulo: "", nivel: 0, contenido: [] };
      seccionActual.contenido.push(l);
    }
  }
  if (seccionActual) secciones.push(seccionActual);

  const getSeveridad = (titulo) => {
    const t = titulo.toLowerCase();
    if (t.includes("irregularidad") || t.includes("riesgo") || t.includes("infracción") || t.includes("incumplimiento") || t.includes("alerta")) return "critico";
    if (t.includes("exceso") || t.includes("desviación") || t.includes("atención") || t.includes("discrepancia")) return "alto";
    if (t.includes("oportunidad") || t.includes("recomendación") || t.includes("mejora") || t.includes("optimización")) return "mejora";
    if (t.includes("situación") || t.includes("conclusión") || t.includes("dictamen") || t.includes("valoración") || t.includes("veredicto")) return "neutral";
    return "info";
  };

  const SEVERIDAD_STYLES = {
    critico: { wrapper:"bg-rose-50 border-rose-300",    badge:"bg-rose-700 text-white",       titulo:"text-rose-800",  borde:"border-l-4 border-rose-500",  icon:"⚠" },
    alto:    { wrapper:"bg-amber-50 border-amber-300",  badge:"bg-amber-600 text-white",       titulo:"text-amber-800", borde:"border-l-4 border-amber-500", icon:"!" },
    mejora:  { wrapper:"bg-sky-50 border-sky-200",      badge:"bg-sky-600 text-white",         titulo:"text-sky-800",   borde:"border-l-4 border-sky-500",   icon:"→" },
    neutral: { wrapper:"bg-slate-50 border-slate-200",  badge:"bg-slate-700 text-white",       titulo:"text-slate-800", borde:"border-l-4 border-slate-400", icon:"≡" },
    info:    { wrapper:"bg-white border-gray-200",      badge:"bg-gray-600 text-white",        titulo:"text-gray-800",  borde:"border-l-4 border-gray-300",  icon:"·" },
  };

  const renderContenido = (lineas, severidad) => {
    const s = SEVERIDAD_STYLES[severidad];
    const grupos = [];
    let lista = [];
    for (const l of lineas) {
      if (l.startsWith("-") || l.startsWith("•") || /^\d+\./.test(l)) {
        lista.push(l.replace(/^[-•]\s*/, "").replace(/^\d+\.\s*/, ""));
      } else {
        if (lista.length) { grupos.push({ tipo:"lista", items:[...lista] }); lista = []; }
        grupos.push({ tipo:"parrafo", texto: l });
      }
    }
    if (lista.length) grupos.push({ tipo:"lista", items:lista });

    return grupos.map((g, i) => {
      if (g.tipo === "parrafo") {
        return <p key={i} className="text-sm text-gray-700 leading-relaxed" dangerouslySetInnerHTML={{__html: g.texto.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/`(.+?)`/g,"<code class='bg-gray-100 px-1 rounded text-xs font-mono'>$1</code>")}}/>;
      }
      return (
        <ul key={i} className="space-y-2 mt-2">
          {g.items.map((item, j) => (
            <li key={j} className="flex gap-2.5 items-start text-sm">
              <span className={`mt-0.5 flex-shrink-0 text-xs font-black ${s.titulo}`}>{s.icon}</span>
              <span className="text-gray-700 leading-relaxed" dangerouslySetInnerHTML={{__html: item.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/art\.\s*(\d+)/g,"<strong class='text-indigo-700'>art. $1</strong>").replace(/\(([A-Z]{2,}\s*\d+\/\d+[^)]*)\)/g,"<em class='text-indigo-600 text-xs'>($1)</em>")}}/>
            </li>
          ))}
        </ul>
      );
    });
  };

  return (
    <div className="space-y-1">
      {/* Cabecera oficial del informe */}
      <div className="bg-gradient-to-r from-slate-900 via-slate-800 to-slate-900 rounded-2xl p-6 text-white mb-6">
        <div className="flex items-start justify-between gap-4 flex-wrap">
          <div>
            <div className="flex items-center gap-3 mb-3">
              <div className="w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center border border-white/20">
                <svg viewBox="0 0 24 24" fill="none" className="w-7 h-7 text-amber-300" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 3v1m0 16v1M4.22 4.22l.707.707M18.364 18.364l.707.707M1 12h1M21 12h1M4.22 19.778l.707-.707M18.364 5.636l.707-.707"/>
                  <circle cx="12" cy="12" r="4" strokeWidth={1.8}/>
                </svg>
              </div>
              <div>
                <div className="text-base font-black tracking-tight">INFORME CONTABLE Y FISCAL</div>
                <div className="text-xs text-white/60 mt-0.5">Inspector Tributario · Derecho Económico y Financiero</div>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-x-8 gap-y-1 text-xs text-white/60 mt-2">
              <span>Período analizado: <span className="text-white font-bold">{MESES_ES[mes]} {anio}</span></span>
              <span>Carácter: <span className="text-amber-300 font-bold">ORIENTATIVO</span></span>
              <span>Emitido: <span className="text-white font-bold">{new Date().toLocaleDateString("es-ES",{day:"2-digit",month:"long",year:"numeric"})}</span></span>
              <span>Base normativa: <span className="text-white font-bold">LIRPF · LIVA · LGT · RIRPF</span></span>
            </div>
          </div>
          <button onClick={onExport}
            className="flex items-center gap-2 px-4 py-2.5 bg-white/10 hover:bg-white/20 border border-white/20 rounded-xl text-xs font-bold transition-colors flex-shrink-0">
            <svg viewBox="0 0 24 24" fill="none" className="w-4 h-4" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/>
            </svg>
            Exportar PDF
          </button>
        </div>
      </div>

      {/* Secciones del informe */}
      {secciones.filter(s => s.titulo || s.contenido.length).map((sec, i) => {
        const sev = getSeveridad(sec.titulo);
        const s   = SEVERIDAD_STYLES[sev];
        if (sec.nivel === 0 && !sec.titulo) {
          return (
            <div key={i} className="px-2 space-y-2">
              {renderContenido(sec.contenido, "info")}
            </div>
          );
        }
        return (
          <div key={i} className={`border rounded-xl overflow-hidden ${s.wrapper}`}>
            <div className={`flex items-center gap-3 px-5 py-3.5 ${s.borde}`}>
              <span className={`text-xs font-black px-2.5 py-1 rounded-full ${s.badge}`}>{s.icon} {sev === "critico" ? "ALERTA" : sev === "alto" ? "AVISO" : sev === "mejora" ? "MEJORA" : sev === "neutral" ? "DICTAMEN" : "INFO"}</span>
              <span className={`font-black text-sm ${s.titulo}`}>{sec.titulo}</span>
            </div>
            <div className={`px-5 py-4 space-y-2 ${sec.nivel === 2 ? "bg-white/50" : ""}`}>
              {renderContenido(sec.contenido, sev)}
            </div>
          </div>
        );
      })}

      {/* Pie legal */}
      <div className="mt-6 p-4 bg-gray-50 border border-gray-200 rounded-xl text-xs text-gray-500 leading-relaxed">
        <strong>Advertencia legal:</strong> este informe tiene carácter exclusivamente orientativo y no constituye asesoramiento fiscal, jurídico ni financiero vinculante. Las conclusiones se basan en los datos aportados por el usuario y no suplen la intervención de un asesor fiscal colegiado, gestor administrativo o abogado especializado en derecho tributario. La normativa fiscal puede haber sido modificada. Consulta siempre con un profesional antes de adoptar decisiones con trascendencia tributaria.
      </div>
    </div>
  );
}

