// ── Mini-gráficas SVG por sección ─────────────────────
const MiniSparkline = ({ values=[], color="#3b82f6", height=32 }) => {
  if (!values.length) return null;
  const max = Math.max(...values, 1);
  const w = 120, h = height;
  const pts = values.map((v,i) => {
    const x = values.length === 1 ? w/2 : (i / (values.length-1)) * w;
    const y = h - (v/max)*h;
    return `${x},${y}`;
  }).join(" ");
  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} className="opacity-70">
      <polyline points={pts} fill="none" stroke={color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
      {values.length > 0 && <circle cx={values.length===1?w/2:(values.length-1)/(values.length-1)*w} cy={h-(values[values.length-1]/max)*h} r="2.5" fill={color}/>}
    </svg>
  );
};

const MiniBarras = ({ values=[], colors=[], height=32 }) => {
  if (!values.length) return null;
  const max = Math.max(...values, 1);
  const w = 120, h = height;
  const bw = Math.max(4, w/values.length - 2);
  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} className="opacity-80">
      {values.map((v,i)=>{
        const bh = (v/max)*h;
        const x = (i/(values.length))*(w) + 1;
        return <rect key={i} x={x} y={h-bh} width={bw} height={bh} rx="1.5" fill={colors[i%colors.length]||"#6366f1"}/>;
      })}
    </svg>
  );
};


