// ── Header de sección con mini-gráfica ────────────────
function SectionHeader({ view, vCount, gCount, pendCount, tCount, miniChartData }) {
  const mcd = miniChartData || [];
  const CFG = {
    dashboard:    { title:"Panel General",       subtitle:"Resumen consolidado de tu contabilidad",        color:"#0f172a", chartType:"sparkline", dataKey:"ventas",         chartColor:"#10b981" },
    facturas:     { title:"Todas las facturas",  subtitle:"Historial completo de documentos",              color:"#6366f1", chartType:"barras",     dataKey:"total",          chartColor:"#6366f1" },
    ventas:       { title:"Facturas emitidas",   subtitle:`${vCount} documentos de venta`,                 color:"#10b981", chartType:"sparkline",  dataKey:"ventas",         chartColor:"#10b981" },
    gastos:       { title:"Facturas recibidas",  subtitle:`${gCount} documentos de gasto`,                 color:"#ef4444", chartType:"sparkline",  dataKey:"gastos",         chartColor:"#ef4444" },
    saldos:       { title:"Saldos pendientes",   subtitle:`${pendCount} facturas sin liquidar`,            color:"#f59e0b", chartType:"barras",     dataKey:"ventas",         chartColor:"#f59e0b" },
    trabajadores: { title:"Personal",            subtitle:`${tCount} trabajadores activos`,                color:"#8b5cf6", chartType:null },
    nominas:      { title:"Nóminas",             subtitle:"Costes laborales y retenciones",                color:"#7c3aed", chartType:"sparkline",  dataKey:"nominas",        chartColor:"#7c3aed" },
    actividades:  { title:"Actividades IAE",     subtitle:"Epígrafes y actividades económicas",            color:"#0ea5e9", chartType:null },
    mod347:       { title:"Modelo 347",          subtitle:"Operaciones con terceros > 3.005,06 €",         color:"#0284c7", chartType:null },
    contactos:    { title:"Directorio",          subtitle:"Clientes y proveedores registrados",            color:"#d97706", chartType:null },
    extracto:     { title:"Asesor IA Fiscal",    subtitle:"Análisis de extracto bancario · Inspector tributario", color:"#0f766e", chartType:null },
    nueva:        { title:"Nueva factura",       subtitle:"Emite o registra un documento",                color:"#059669", chartType:null },
  };
  const cfg = CFG[view] || CFG.dashboard;
  const vals = mcd.map(d => cfg.dataKey === "total" ? (d.ventas + d.gastos) : (d[cfg.dataKey] || 0));
  return (
    <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 bg-white flex-shrink-0"
      style={{minHeight:68}}>
      <div className="flex items-center gap-4">
        <div className="w-1 h-10 rounded-full flex-shrink-0" style={{background:cfg.color}}/>
        <div>
          <div className="font-black text-gray-900 text-base leading-tight">{cfg.title}</div>
          <div className="text-xs text-gray-400 mt-0.5">{cfg.subtitle}</div>
        </div>
      </div>
      {cfg.chartType && mcd.length > 0 && (
        <div className="hidden md:flex items-end gap-2">
          <div className="flex items-end gap-1 mr-2">
            {mcd.map((d,i) => (
              <div key={i} className="text-center">
                <div className="text-xs text-gray-300" style={{fontSize:9}}>{d.label}</div>
              </div>
            ))}
          </div>
          {cfg.chartType === "sparkline"
            ? <MiniSparkline values={vals} color={cfg.chartColor}/>
            : <MiniBarras values={vals} colors={[cfg.chartColor, cfg.chartColor+"99"]}/>
          }
        </div>
      )}
    </div>
  );
}


