// PANTALLA DE LOGIN
// ════════════════════════════════════════════════════════════
function LoginScreen({ onLogin }) {
  const [email, setEmail]       = useState("");
  const [pass,  setPass]        = useState("");
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);
  const [modo, setModo]         = useState("login"); // login | registro | reset

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) {
      if (error.message.includes("Invalid login")) setError("Email o contraseña incorrectos.");
      else if (error.message.includes("Email not confirmed")) setError("Debes confirmar tu email antes de entrar. Revisa tu bandeja de entrada.");
      else if (error.message.includes("Invalid API key") || error.message.includes("Failed to fetch")) setError("Error de conexión con la base de datos. Comprueba la configuración.");
      else setError(error.message);
    }
    setLoading(false);
  };

  const handleRegistro = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    const { error } = await supabase.auth.signUp({ email, password: pass });
    if (error) setError(error.message);
    else setError("Revisa tu correo para confirmar la cuenta.");
    setLoading(false);
  };

  const handleReset = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    const { error } = await supabase.auth.resetPasswordForEmail(email);
    if (error) setError(error.message);
    else setError("Correo de recuperación enviado.");
    setLoading(false);
  };

  const submit = modo === "login" ? handleLogin : modo === "registro" ? handleRegistro : handleReset;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-800 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-8">
        <div className="text-center mb-8">
          <div className="w-12 h-12 bg-slate-900 rounded-xl mx-auto mb-3 flex items-center justify-center">
            <svg viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" className="w-6 h-6">
              <path d="M9 7H6a2 2 0 00-2 2v9a2 2 0 002 2h12a2 2 0 002-2V9a2 2 0 00-2-2h-3M9 7V5a2 2 0 012-2h2a2 2 0 012 2v2M9 7h6"/>
            </svg>
          </div>
          <h1 className="text-xl font-bold text-slate-900">ContaAuto</h1>
          <p className="text-sm text-slate-500 mt-1">
            {modo === "login" ? "Accede a tu cuenta" : modo === "registro" ? "Crear cuenta nueva" : "Recuperar contraseña"}
          </p>
        </div>

        <form onSubmit={submit} className="space-y-4">
          <div>
            <label className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Email</label>
            <input
              type="email" required value={email} onChange={e => setEmail(e.target.value)}
              className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-slate-400"
              placeholder="tu@email.com"
            />
          </div>
          {modo !== "reset" && (
            <div>
              <label className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Contraseña</label>
              <input
                type="password" required value={pass} onChange={e => setPass(e.target.value)}
                className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-slate-400"
                placeholder="••••••••"
              />
            </div>
          )}
          {error && (
            <p className={`text-xs px-3 py-2 rounded-lg ${error.includes("enviado") || error.includes("confirmar") ? "bg-green-50 text-green-700" : "bg-rose-50 text-rose-700"}`}>
              {error}
            </p>
          )}
          <button
            type="submit" disabled={loading}
            className="w-full bg-slate-900 hover:bg-slate-700 disabled:bg-slate-400 text-white font-semibold py-3 rounded-xl text-sm transition-colors"
          >
            {loading ? "Cargando..." : modo === "login" ? "Entrar" : modo === "registro" ? "Crear cuenta" : "Enviar correo"}
          </button>
        </form>

        <div className="mt-5 text-center space-y-2">
          {modo === "login" && (
            <>
              <button onClick={() => { setModo("registro"); setError(""); }} className="text-xs text-slate-500 hover:text-slate-700 block w-full">
                ¿No tienes cuenta? Regístrate
              </button>
              <button onClick={() => { setModo("reset"); setError(""); }} className="text-xs text-slate-400 hover:text-slate-600 block w-full">
                Olvidé mi contraseña
              </button>
            </>
          )}
          {modo !== "login" && (
            <button onClick={() => { setModo("login"); setError(""); }} className="text-xs text-slate-500 hover:text-slate-700">
              Volver al inicio de sesión
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// APLICACIÓN PRINCIPAL
// ════════════════════════════════════════════════════════════
function ContaAutoApp() {
  const [user,          setUser]         = useState(null);
  const [loadingData,   setLoadingData]  = useState(true);
  const [facturas,      setFacturas]     = useState([]);
  const [contactos,     setContactos]    = useState([]);
  const [trabajadores,  setTrabajadores] = useState([]);
  const [nominas,       setNominas]      = useState([]);
  const [actividades,   setActividades]  = useState(ACTS_INIT);
  const [logo,          setLogo]         = useState(LOGO_EMPRESA); // logotipo Digital Conect

  const [pantallaBienvenida, setPantallaBienvenida] = useState(false);
  const [view,       setView]       = useState("dashboard");
  const [subview,    setSubview]    = useState(null);
  const [editing,    setEditing]    = useState(null);
  const [viewing,    setViewing]    = useState(null);  // { tipo: "factura"|"nomina", data }
  const [creada,     setCreada]     = useState(null);  // factura recién creada → modal post-creación

  const [periodMode,  setPeriodMode]  = useState("mes");
  const [periodValue, setPeriodValue] = useState(cm);
  const [periodYear,  setPeriodYear]  = useState(cy);

  const goView    = (v) => { setView(v); setSubview(null); setEditing(null); };
  const closeForm = ()  => { setSubview(null); setEditing(null); };
  const onEnter   = (v) => { setPantallaBienvenida(false); if(v!=="dashboard") { setView(v); setSubview(null); setEditing(null); } else { setView("dashboard"); } };

  // ── Auth ──────────────────────────────────────────────
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session }, error }) => {
      if (error) console.error("Error obteniendo sesión:", error.message);
      setUser(session?.user ?? null);
      setLoadingData(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (!session) setLoadingData(false);
    });
    return () => subscription.unsubscribe();
  }, []);

  // ── Carga inicial de datos ────────────────────────────
  const cargarDatos = useCallback(async () => {
    if (!user) return;
    const uid = user.id;
    const [rf, rc, rt, rn] = await Promise.all([
      supabase.from("facturas").select("*").eq("user_id", uid).order("fecha", { ascending: false }),
      supabase.from("contactos").select("*").eq("user_id", uid).order("nombre"),
      supabase.from("trabajadores").select("*").eq("user_id", uid).order("nombre"),
      supabase.from("nominas").select("*").eq("user_id", uid).order("anio", { ascending: false }),
    ]);
    if (rf.error) console.error("Error cargando facturas:", rf.error.message);
    if (rc.error) console.error("Error cargando contactos:", rc.error.message);
    if (rt.error) console.error("Error cargando trabajadores:", rt.error.message);
    if (rn.error) console.error("Error cargando nóminas:", rn.error.message);
    if (rf.data) setFacturas(rf.data.map(dbToFactura));
    if (rc.data) setContactos(rc.data);
    if (rt.data) setTrabajadores(rt.data.map(dbToTrabajador));
    if (rn.data) {
      const trabajadoresData = rt.data || [];
      setNominas(rn.data.map(n => dbToNomina(n, trabajadoresData)));
    }
  }, [user]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  // ── Facturas ──────────────────────────────────────────
  const saveFactura = async (f) => {
    const uid = user?.id;
    const row = {
      user_id: uid, tipo: f.tipo, numero: f.numero, fecha: f.fecha,
      actividad: f.actividad || "",
      cliente_nombre: f.cliente || f.clienteNombre || f.cliente_nombre || "",
      cliente_nif: f.nif || f.clienteNif || f.cliente_nif || "",
      cliente_email: f.email || f.clienteEmail || f.cliente_email || "",
      cliente_telefono: f.telefono || f.clienteTelefono || f.cliente_telefono || "",
      cliente_direccion: f.direccion || f.clienteDireccion || f.cliente_direccion || "",
      lineas: f.lineas || [],
      retencion_pct: f.retencionPct ?? f.retencion_pct ?? 0,
      aplicar_recargo: f.aplicarRecargo ?? f.aplicar_recargo ?? false,
      cobrado: f.cobrado ?? false,
      pagado: f.pagado ?? false,
      notas: f.notas || "",
      documento_url: f.documento_url || null,
      documento_nombre: f.documento_nombre || null,
    };
    if (editing) {
      const { data, error } = await supabase.from("facturas").update(row).eq("id", editing.id).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) {
        const updated = dbToFactura(data);
        setFacturas(p => p.map(x => x.id === editing.id ? updated : x));
        setContactos(p => upsertContacto(p, updated));
      }
      closeForm(); setView(f.tipo === "venta" ? "ventas" : "gastos");
    } else {
      const { data, error } = await supabase.from("facturas").insert(row).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) {
        const saved = dbToFactura(data);
        setFacturas(p => [saved, ...p]);
        setContactos(p => upsertContacto(p, saved));
        closeForm(); setCreada(saved);
      }
    }
  };
  const delFactura = async (id) => {
    if (!confirm("¿Eliminar factura?")) return;
    const { error } = await supabase.from("facturas").delete().eq("id", id);
    if (error) { alert("Error al eliminar: " + error.message); return; }
    setFacturas(p => p.filter(f => f.id !== id));
    setContactos(p => p.filter(c => c.id !== id)); // limpiar contacto huérfano si procede
  };
  const marcarCobrado = async (id) => {
    const { error } = await supabase.from("facturas").update({ cobrado: true }).eq("id", id);
    if (error) { alert("Error al actualizar: " + error.message); return; }
    setFacturas(p => p.map(f => f.id===id ? {...f, cobrado:true} : f));
  };
  const marcarPagado = async (id) => {
    const { error } = await supabase.from("facturas").update({ pagado: true }).eq("id", id);
    if (error) { alert("Error al actualizar: " + error.message); return; }
    setFacturas(p => p.map(f => f.id===id ? {...f, pagado:true} : f));
  };

  // ── Trabajadores ──────────────────────────────────────
  const saveTrabajador = async (t) => {
    const uid = user?.id;
    const row = {
      user_id: uid, nombre: t.nombre, nif: t.nif, categoria: t.categoria,
      contrato: t.contrato,
      salario_base: t.salarioBase ?? t.salario_base ?? 0,
      activo: t.activo ?? true,
      fecha_alta: t.fechaAlta || t.fecha_alta || null,
      notas: t.notas || "",
    };
    if (editing) {
      const { data, error } = await supabase.from("trabajadores").update(row).eq("id", editing.id).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) setTrabajadores(p => p.map(x => x.id === editing.id ? dbToTrabajador(data) : x));
    } else {
      const { data, error } = await supabase.from("trabajadores").insert(row).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) setTrabajadores(p => [...p, dbToTrabajador(data)]);
    }
    closeForm(); setView("trabajadores");
  };
  const delTrabajador = async (id) => {
    if (!confirm("¿Eliminar?")) return;
    const { error } = await supabase.from("trabajadores").delete().eq("id", id);
    if (error) { alert("Error al eliminar: " + error.message); return; }
    setTrabajadores(p => p.filter(t => t.id !== id));
  };
  const toggleBaja = async (id) => {
    const t = trabajadores.find(x => x.id===id);
    if (!t) return;
    const { error } = await supabase.from("trabajadores").update({ activo: !t.activo }).eq("id", id);
    if (error) { alert("Error al actualizar: " + error.message); return; }
    setTrabajadores(p => p.map(x => x.id===id ? {...x, activo:!x.activo} : x));
  };

  // ── Nóminas ───────────────────────────────────────────
  const saveNomina = async (n) => {
    const uid = user?.id;
    const trab = trabajadores.find(t => t.id === (n.trabajadorId || n.trabajador_id));
    const row = {
      user_id: uid,
      trabajador_id: n.trabajadorId || n.trabajador_id,
      trabajador_nombre: trab?.nombre || n.trabajadorNombre || n.trabajador_nombre || "",
      mes: n.mes, anio: n.anio,
      fecha: n.fecha || `${n.anio}-${String(n.mes+1).padStart(2,"0")}-28`,
      horas_extra: n.horasExtra ?? n.horas_extra ?? 0,
      plus_transporte: n.plusTransporte ?? n.plus_transporte ?? 0,
      otros_conceptos: n.otrosConceptos ?? n.otros_conceptos ?? 0,
      notas: n.notas || "",
    };
    if (editing) {
      const { data, error } = await supabase.from("nominas").update(row).eq("id", editing.id).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) setNominas(p => p.map(x => x.id === editing.id ? dbToNomina(data, trabajadores) : x));
    } else {
      const { data, error } = await supabase.from("nominas").insert(row).select().single();
      if (error) { alert("Error al guardar: " + error.message); return; }
      if (data) setNominas(p => [...p, dbToNomina(data, trabajadores)]);
    }
    closeForm(); setView("nominas");
  };
  const delNomina = async (id) => {
    if (!confirm("¿Eliminar?")) return;
    const { error } = await supabase.from("nominas").delete().eq("id", id);
    if (error) { alert("Error al eliminar: " + error.message); return; }
    setNominas(p => p.filter(n => n.id !== id));
  };

  const vCount = facturas.filter(f=>f.tipo==="venta").length;
  const gCount = facturas.filter(f=>f.tipo==="gasto").length;
  const tCount = trabajadores.filter(t=>t.activo).length;
  const pendCount = facturas.filter(f=>(f.tipo==="venta"&&!f.cobrado)||(f.tipo==="gasto"&&!f.pagado)).length;
  const availYears = useMemo(() => {
    const s = new Set([cy, ...facturas.map(f=>new Date(f.fecha).getFullYear()), ...nominas.map(n=>new Date(n.fecha).getFullYear())]);
    return [...s].sort((a,b)=>b-a);
  }, [facturas, nominas]);
  const datos347 = useMemo(() => calc347(facturas, periodYear), [facturas, periodYear]);
  const count347 = datos347.length;

  const inForm    = !!subview || view==="nueva";
  const showPeriod = !inForm && !["actividades","trabajadores","nueva","mod347","contactos","extracto"].includes(view);

  const handleNuevaFactura = () => { setEditing(null); setSubview(null); setView("nueva"); };

  // Datos para mini-gráficas (últimos 6 meses)
  // IMPORTANTE: este useMemo debe estar ANTES del return anticipado para
  // respetar la regla de hooks (mismo número y orden en cada render)
  const miniChartData = useMemo(() => {
    const baseMonth = periodMode === "mes" ? periodValue : new Date().getMonth();
    const meses6 = Array.from({length:6},(_,i)=>{
      const d = new Date(periodYear, baseMonth - (5-i), 1);
      return { m: d.getMonth(), y: d.getFullYear() };
    });
    return meses6.map(({m,y}) => {
      const fs = facturas.filter(f=>{ const d=new Date(f.fecha); return d.getMonth()===m&&d.getFullYear()===y; });
      const ng = nominas.filter(n=>n.mes===m&&n.anio===y);
      return {
        label: ["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"][m],
        ventas:  fs.filter(f=>f.tipo==="venta").reduce((s,f)=>s+calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo).totalBase,0),
        gastos:  fs.filter(f=>f.tipo==="gasto").reduce((s,f)=>s+calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo).totalBase,0),
        nominas: ng.reduce((s,n)=>s+calcNomina(n).costeEmpresa,0),
      };
    });
  }, [facturas, nominas, periodValue, periodYear]);

  // Guards de autenticación y carga (ANTES del return anticipado de bienvenida)
  if (loadingData) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <div className="text-white text-sm">Cargando...</div>
      </div>
    );
  }
  if (!user) {
    return <LoginScreen />;
  }

  // Early return DESPUÉS de todos los hooks
  if (pantallaBienvenida) {
    return <PantallaBienvenida onEnter={onEnter} facturas={facturas} contactos={contactos} nominas={nominas}/>;
  }

  return (
    <div className="flex h-screen overflow-hidden" style={{background:"#f1f5f9", fontFamily:"'DM Sans','Segoe UI',sans-serif"}}>

      {/* ══ SIDEBAR IZQUIERDO ══════════════════════════════ */}
      <aside className="flex flex-col flex-shrink-0 bg-slate-900 text-white overflow-y-auto"
        style={{width:220, minWidth:220, boxShadow:"2px 0 12px rgba(0,0,0,.18)"}}>

        {/* Logo */}
        <div className="flex items-center gap-3 px-4 py-4 border-b" style={{borderColor:"rgba(255,255,255,.07)"}}>
          {logo
            ? <img src={logo} alt="logo" className="h-9 object-contain" style={{maxWidth:110}}/>
            : <div className="w-9 h-9 bg-emerald-500 rounded-xl flex items-center justify-center flex-shrink-0"><span className="text-white text-xs font-black">CA</span></div>
          }
          <div className="min-w-0">
            <div className="text-sm font-black text-white truncate leading-tight">ContaAuto</div>
            <div className="text-xs truncate" style={{color:"rgba(255,255,255,.35)"}}>Autónomos España</div>
          </div>
        </div>

        {/* Botón nueva factura destacado */}
        <div className="px-3 py-3 border-b" style={{borderColor:"rgba(255,255,255,.06)"}}>
          <button onClick={handleNuevaFactura}
            className="w-full flex items-center justify-center gap-2 py-2.5 rounded-xl font-black text-sm transition-all"
            style={{background:"linear-gradient(135deg,#10b981,#059669)", boxShadow:"0 2px 8px rgba(16,185,129,.3)"}}>
            {Ico.plus} Nueva factura
          </button>
        </div>

        {/* Navegación agrupada */}
        <nav className="flex-1 py-2">
          {NAV_GROUPS.map(grp => {
            const items = NAV_SIDEBAR.filter(n => n.group === grp.id);
            return (
              <div key={grp.id} className="mb-1">
                <div className="px-4 pt-3 pb-1 text-xs font-bold uppercase tracking-widest" style={{color:"rgba(255,255,255,.25)"}}>{grp.label}</div>
                {items.map(n => {
                  const active = view === n.id && !subview;
                  const isNueva = n.id === "nueva";
                  return (
                    <button key={n.id}
                      onClick={() => isNueva ? handleNuevaFactura() : goView(n.id)}
                      className="w-full flex items-center justify-between px-4 py-2.5 text-sm font-medium transition-all rounded-none"
                      style={{
                        background: active ? "rgba(255,255,255,.1)" : "transparent",
                        color: active ? "#fff" : "rgba(255,255,255,.55)",
                        borderLeft: active ? "3px solid #10b981" : "3px solid transparent",
                      }}
                      onMouseEnter={e=>{ if(!active) { e.currentTarget.style.background="rgba(255,255,255,.05)"; e.currentTarget.style.color="rgba(255,255,255,.85)"; }}}
                      onMouseLeave={e=>{ if(!active) { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="rgba(255,255,255,.55)"; }}}>
                      <div className="flex items-center gap-2.5 min-w-0">
                        <NavIcon id={n.iconId}/>
                        <span className="truncate">{n.label}</span>
                      </div>
                      <div className="flex-shrink-0 ml-1">
                        {n.id==="ventas"       && vCount>0     && <span className="text-xs bg-emerald-500/20 text-emerald-300 px-1.5 py-0.5 rounded-full font-bold">{vCount}</span>}
                        {n.id==="gastos"       && gCount>0     && <span className="text-xs bg-rose-500/20 text-rose-300 px-1.5 py-0.5 rounded-full font-bold">{gCount}</span>}
                        {n.id==="trabajadores" && tCount>0     && <span className="text-xs bg-violet-500/20 text-violet-300 px-1.5 py-0.5 rounded-full font-bold">{tCount}</span>}
                        {n.id==="nominas"      && nominas.length>0 && <span className="text-xs bg-purple-500/20 text-purple-300 px-1.5 py-0.5 rounded-full font-bold">{nominas.length}</span>}
                        {n.id==="saldos"       && pendCount>0  && <span className="text-xs bg-orange-500/20 text-orange-300 px-1.5 py-0.5 rounded-full font-bold">{pendCount}</span>}
                        {n.id==="mod347"       && count347>0   && <span className="text-xs bg-sky-500/20 text-sky-300 px-1.5 py-0.5 rounded-full font-bold">{count347}</span>}
                        {n.id==="contactos"    && contactos.length>0 && <span className="text-xs bg-slate-500/20 text-slate-300 px-1.5 py-0.5 rounded-full font-bold">{contactos.length}</span>}
                        {n.id==="extracto"     && <span className="text-xs bg-teal-500/20 text-teal-300 px-1.5 py-0.5 rounded-full font-bold">IA</span>}
                      </div>
                    </button>
                  );
                })}
              </div>
            );
          })}
          {/* Subvista activa */}
          {subview && (
            <div className="mx-3 mt-1 px-3 py-2 rounded-xl text-xs font-bold text-sky-300 bg-sky-500/10 border border-sky-500/20">
              {{"new-nomina":"Generar nómina","edit-nomina":"Editar nómina","new-trabajador":"Alta trabajador","edit-trabajador":"Editar trabajador","edit-factura":"Editar factura"}[subview]}
            </div>
          )}
        </nav>

        {/* Footer del sidebar */}
        <div className="px-4 py-4 border-t" style={{borderColor:"rgba(255,255,255,.07)"}}>
          <button onClick={() => setPantallaBienvenida(true)}
            className="w-full flex items-center gap-2 py-2 px-3 rounded-xl text-xs font-semibold transition-colors"
            style={{color:"rgba(255,255,255,.4)"}}
            onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,.06)";e.currentTarget.style.color="rgba(255,255,255,.7)"}}
            onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,.4)"}}>
            <svg viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5 flex-shrink-0">
              <path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z"/>
            </svg>
            Pantalla de inicio
          </button>
          <div className="mt-2 text-center text-xs" style={{color:"rgba(255,255,255,.18)"}}>ContaAuto v2 · España</div>
          {user && (
            <div className="mt-3 px-3">
              <div className="text-xs truncate mb-1" style={{color:"rgba(255,255,255,.35)"}}>{user.email}</div>
              <button
                onClick={() => supabase.auth.signOut()}
                className="w-full text-left text-xs px-3 py-2 rounded-lg transition-colors"
                style={{color:"rgba(255,255,255,.5)", background:"transparent"}}
                onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,.08)";e.currentTarget.style.color="rgba(255,255,255,.8)"}}
                onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,.5)"}}
              >
                Cerrar sesión
              </button>
            </div>
          )}
        </div>
      </aside>

      {/* ══ PANEL DERECHO ══════════════════════════════════ */}
      <main className="flex-1 flex flex-col overflow-hidden">

        {/* Topbar compacto */}
        <div className="flex-shrink-0 flex items-center justify-between px-6 py-3 bg-white border-b border-gray-200" style={{boxShadow:"0 1px 3px rgba(0,0,0,.04)"}}>
          <div className="flex items-center gap-3">
            <div className="hidden md:flex items-center gap-2 text-xs text-gray-500">
              <span><span className="inline-block w-1.5 h-1.5 bg-emerald-500 rounded-full mr-1 align-middle"/>{vCount} ventas</span>
              <span className="text-gray-200">·</span>
              <span><span className="inline-block w-1.5 h-1.5 bg-rose-500 rounded-full mr-1 align-middle"/>{gCount} gastos</span>
              <span className="text-gray-200">·</span>
              <span><span className="inline-block w-1.5 h-1.5 bg-violet-500 rounded-full mr-1 align-middle"/>{tCount} trab.</span>
              {pendCount > 0 && <><span className="text-gray-200">·</span><span className="text-amber-600 font-bold"><span className="inline-block w-1.5 h-1.5 bg-amber-400 rounded-full mr-1 align-middle"/>{pendCount} pend.</span></>}
            </div>
          </div>
          <div className="flex items-center gap-2">
            {showPeriod && (
              <PeriodSelector mode={periodMode} setMode={setPeriodMode} value={periodValue} setValue={setPeriodValue} year={periodYear} setYear={setPeriodYear} facturas={facturas} nominas={nominas}/>
            )}
            <button onClick={() => { setSubview("new-nomina"); setEditing(null); setView("nominas"); }}
              className="hidden md:flex items-center gap-1.5 text-violet-700 bg-violet-50 border border-violet-200 hover:bg-violet-100 text-xs font-bold px-3 py-2 rounded-xl transition-colors">
              {Ico.plus} Nómina
            </button>
          </div>
        </div>

        {/* Alertas */}
        <AlertasSistema facturas={facturas} onGoSaldos={() => goView("saldos")} onGo347={() => goView("mod347")} year={periodYear}/>

        {/* Header de sección con mini-gráfica */}
        {!inForm && (
          <SectionHeader view={view} vCount={vCount} gCount={gCount} pendCount={pendCount} tCount={tCount} miniChartData={miniChartData}/>
        )}

        {/* Contenido principal scrollable */}
        <div className="flex-1 overflow-y-auto">
          <div className="p-6">

            {/* NUEVA FACTURA */}
            {view==="nueva" && !subview && (
              <FacturaForm actividades={actividades} facturas={facturas} onSave={saveFactura} onCancel={() => goView("facturas")} initial={editing} logo={logo} setLogo={setLogo} contactos={contactos} userId={user?.id}/>
            )}
            {subview==="new-trabajador"    && <TrabajadorForm onSave={saveTrabajador} onCancel={closeForm}/>}
            {subview==="edit-trabajador"   && <TrabajadorForm onSave={saveTrabajador} onCancel={closeForm} initial={editing}/>}
            {subview==="new-nomina"        && <NominaForm trabajadores={trabajadores.filter(t=>t.activo)} onSave={saveNomina} onCancel={closeForm}/>}
            {subview==="edit-nomina"       && <NominaForm trabajadores={trabajadores.filter(t=>t.activo)} onSave={saveNomina} onCancel={closeForm} initial={editing}/>}
            {subview==="edit-factura"      && <FacturaForm actividades={actividades} facturas={facturas} onSave={saveFactura} onCancel={closeForm} initial={editing} logo={logo} setLogo={setLogo} contactos={contactos} userId={user?.id}/>}

            {!subview && view!=="nueva" && (
              <>
                {view==="dashboard"    && <Dashboard facturas={facturas} nominas={nominas} trabajadores={trabajadores} periodMode={periodMode} periodValue={periodValue} periodYear={periodYear}/>}
                {view==="facturas"     && <ListaFacturas facturas={facturas} logo={logo} onEdit={f=>{setEditing(f);setSubview("edit-factura");}} onDelete={delFactura} onView={f=>setViewing({tipo:"factura",data:f})} tipoFiltro="todas" periodMode={periodMode} periodValue={periodValue} periodYear={periodYear}/>}
                {view==="ventas"       && <ListaFacturas facturas={facturas} logo={logo} onEdit={f=>{setEditing(f);setSubview("edit-factura");}} onDelete={delFactura} onView={f=>setViewing({tipo:"factura",data:f})} tipoFiltro="venta" periodMode={periodMode} periodValue={periodValue} periodYear={periodYear}/>}
                {view==="gastos"       && <ListaFacturas facturas={facturas} logo={logo} onEdit={f=>{setEditing(f);setSubview("edit-factura");}} onDelete={delFactura} onView={f=>setViewing({tipo:"factura",data:f})} tipoFiltro="gasto" periodMode={periodMode} periodValue={periodValue} periodYear={periodYear}/>}
                {view==="saldos"       && <VistaSaldosPendientes facturas={facturas} onMarcarCobrado={marcarCobrado} onMarcarPagado={marcarPagado} onView={f=>setViewing({tipo:"factura",data:f})}/>}
                {view==="trabajadores" && <VistaTrabajadores trabajadores={trabajadores} onNew={() => {setEditing(null);setSubview("new-trabajador");}} onEdit={t=>{setEditing(t);setSubview("edit-trabajador");}} onDelete={delTrabajador} onBaja={toggleBaja}/>}
                {view==="nominas"      && <VistaNominas nominas={nominas} trabajadores={trabajadores} onNew={() => {setEditing(null);setSubview("new-nomina");}} onView={n=>setViewing({tipo:"nomina",data:n})} onDelete={delNomina} periodMode={periodMode} periodValue={periodValue} periodYear={periodYear}/>}
                {view==="actividades"  && <GestionActividades actividades={actividades} setActividades={setActividades}/>}
                {view==="mod347"       && <Vista347 facturas={facturas} year={periodYear} availYears={availYears}/>}
                {view==="contactos"    && <VistaContactos contactos={contactos} setContactos={setContactos} facturas={facturas} onView={f=>setViewing({tipo:"factura",data:f})}/>}
                {view==="extracto"     && <VistaExtractoBancario facturas={facturas} nominas={nominas}/>}
              </>
            )}

            <div className="pt-8 text-center">
              <p className="text-xs text-gray-300">ContaAuto · Gestión contable y laboral para autónomos en España · Consulta con tu asesor fiscal</p>
            </div>
          </div>
        </div>
      </main>

      {/* Modales */}
      {viewing?.tipo==="factura" && (
        <DetalleFacturaModal factura={viewing.data} logo={logo} onClose={() => setViewing(null)}
          onEdit={f=>{setViewing(null);setEditing(f);setSubview("edit-factura");}} onDelete={delFactura}/>
      )}
      {viewing?.tipo==="nomina" && (
        <DetalleNominaModal nomina={viewing.data} trabajadores={trabajadores} onClose={() => setViewing(null)} onDelete={delNomina}/>
      )}
      {creada && (
        <FacturaCreadaModal
          factura={creada} logo={logo}
          onEdit={f => { setCreada(null); setEditing(f); setSubview("edit-factura"); setView("facturas"); }}
          onClose={() => { setCreada(null); setView(creada.tipo==="venta"?"ventas":"gastos"); }}
        />
      )}
    </div>
  );
}

export default function ContaAuto() {
  return <ContaAutoApp />;
}
